Refined validation functions for better accuracy and user feedback.

```typescript
// utils/validation.ts

/**
 * Validates a required text field.
 * @param value The string to check.
 * @param fieldName The name of the field to display in the error message.
 * @returns Error message or null.
 */
export const validateRequired = (value: string, fieldName: string = 'هذا الحقل'): string | null => {
    if (!value || !value.trim()) {
        return `${fieldName} مطلوب.`;
    }
    return null;
};

/**
 * Validates an email address.
 * @param email The email string to validate.
 * @returns An error message string if invalid, otherwise null.
 */
export const validateEmail = (email: string): string | null => {
    if (!email || !email.trim()) return null; // Optional field
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email.trim())) {
        return "صيغة البريد الإلكتروني غير صحيحة.";
    }
    return null;
};

/**
 * Validates an Egyptian phone number.
 * Must be 11 digits and start with 010, 011, 012, or 015.
 * Handles cleaning of spaces or dashes.
 * @param phone The phone number string to validate.
 * @returns An error message string if invalid, otherwise null.
 */
export const validatePhone = (phone: string): string | null => {
    if (!phone || !phone.trim()) return null; // Optional field

    // Remove common separators like spaces or dashes
    const cleanPhone = phone.replace(/[\s-]/g, '');

    const phoneRegex = /^01[0125][0-9]{8}$/;
    if (!phoneRegex.test(cleanPhone)) {
        return "يجب أن يكون رقم الهاتف مصريًا صالحًا (11 رقمًا ويبدأ بـ 01).";
    }
    return null;
};

/**
 * Validates an Egyptian National ID.
 * Must be 14 digits.
 * @param id The National ID string to validate.
 * @returns An error message string if invalid, otherwise null.
 */
export const validateNationalId = (id: string): string | null => {
    if (!id || !id.trim()) return "الرقم القومي مطلوب.";

    const cleanId = id.trim();
    const nationalIdRegex = /^\d{14}$/;

    if (!nationalIdRegex.test(cleanId)) {
        return "يجب أن يتكون الرقم القومي من 14 رقمًا.";
    }
    return null;
};

/**
 * Validates an Egyptian Tax ID number.
 * Must be in the format XXX-XXX-XXX.
 * @param id The Tax ID string to validate.
 * @returns An error message string if invalid, otherwise null.
 */
export const validateTaxId = (id: string): string | null => {
    if (!id || !id.trim()) return null; // Optional field

    const cleanId = id.trim();
    const taxIdRegex = /^\d{3}-\d{3}-\d{3}$/;

    if (!taxIdRegex.test(cleanId)) {
        return "يجب أن تكون صيغة الرقم الضريبي XXX-XXX-XXX.";
    }
    return null;
};

