  const linkOperationToJournalEntry = (operationId: string, journalEntryId: string) => {
    const operation = operations.find(op => op.id === operationId);
    const journalEntry = journalEntries.find(je => je.id === journalEntryId);

    if (!operation || !journalEntry) {
        alert('لم يتم العثور على العملية أو قيد اليومية!');
        return;
    }

    // 1. Update operation with the journal entry ID
    const updatedOperation = { ...operation, journalEntryId };
    setOperations(prev => prev.map(op => op.id === operationId ? updatedOperation : op));

    // 2. Update journal entry's reference number for a two-way link, if it's empty
    if (!journalEntry.referenceNumber) {
        const updatedJournalEntry = { ...journalEntry, referenceNumber: operation.code };
        setJournalEntries(prev => prev.map(je => je.id === journalEntryId ? updatedJournalEntry : je));
    }

    setIsFormDirty(true);
    alert(`تم ربط العملية ${operation.code} بالقيد بنجاح.`);
  };

  // --- Document Management Functions ---
  const MAX_FILE_SIZE = 2 * 1024 * 1024; // 2 MB limit

  const addDocument = (file: File, linkedToId: string, linkedToType: 'account' | 'operation'): Promise<void> => {
      return new Promise((resolve, reject) => {
          if (file.size > MAX_FILE_SIZE) {
              const errorMsg = `حجم الملف يتجاوز الحد المسموح به (2 ميجابايت). للحفاظ على أداء التطبيق، لا يمكن تخزين الملفات الكبيرة مباشرة.`;
              alert(errorMsg);
              reject(new Error(errorMsg));
              return;
          }

          const reader = new FileReader();
          reader.readAsDataURL(file);
          reader.onload = () => {
              const newDocument: Document = {
                  id: uuidv4(),
                  name: file.name,
                  type: file.type,
                  size: file.size,
                  data: reader.result as string,
                  linkedToId: linkedToId,
                  linkedToType: linkedToType,
                  uploadDate: new Date().toISOString(),
              };
              setDocuments(prev => [...prev, newDocument]);
              setIsFormDirty(true);
              resolve();
          };
          reader.onerror = (error) => {
              console.error("Error reading file:", error);
              reject(error);
          };
      });
  };

