        setIsOpen(false);
        setSearchTerm('');
    };

    return (
        <div className="relative w-full" ref={wrapperRef}>
            <div 
                className={`flex items-center justify-between w-full p-2 bg-primary rounded-lg shadow-neumo-inset-sm cursor-pointer border ${hasError ? 'border-red-400' : 'border-transparent'}`}
