  const addDocument = (file: File, linkedToId: string, linkedToType: 'account' | 'operation'): Promise<void> => {
      return new Promise((resolve, reject) => {
          if (file.size > MAX_FILE_SIZE) {
              const errorMsg = `حجم الملف يتجاوز الحد المسموح به (2 ميجابايت). للحفاظ على أداء التطبيق، لا يمكن تخزين الملفات الكبيرة مباشرة.`;
              alert(errorMsg);
              reject(new Error(errorMsg));
              return;
          }

          const reader = new FileReader();
          reader.readAsDataURL(file);
          reader.onload = () => {
              const newDocument: Document = {
                  id: uuidv4(),
                  name: file.name,
                  type: file.type,
                  size: file.size,
                  data: reader.result as string,
                  linkedToId: linkedToId,
                  linkedToType: linkedToType,
                  uploadDate: new Date().toISOString(),
              };
              setDocuments(prev => [...prev, newDocument]);
              setIsFormDirty(true);
              resolve();
          };
          reader.onerror = (error) => {
              console.error("Error reading file:", error);
              reject(error);
          };
      });
  };

