                            {calculations.scheduleTaxAmount > 0 && (
                                <tr>
                                    <td className="font-bold p-2">ضريبة جدول (10%)</td>
                                    <td className="p-2 text-right font-mono">{formatCurrency(calculations.scheduleTaxAmount)}</td>
                                </tr>
