  );
};


// --- Account Statement Component ---
interface AccountStatementProps {
    client: Account;
    operations: Operation[];
    onClose: () => void;
}

const AccountStatement: React.FC<AccountStatementProps> = ({ client, operations, onClose }) => {
    const [fromDate, setFromDate] = useState<string>(() => {
        const date = new Date();
        date.setMonth(date.getMonth() - 1);
        return date.toISOString().split('T')[0];
    });
    const [toDate, setToDate] = useState<string>(new Date().toISOString().split('T')[0]);

    const clientOperations = useMemo(() => {
        return operations
            .filter(op => op.clientId === client.id && op.creationDate >= fromDate && op.creationDate <= toDate)
            .sort((a, b) => new Date(a.creationDate).getTime() - new Date(b.creationDate).getTime());
    }, [client.id, operations, fromDate, toDate]);

    const totalRevenue = clientOperations.reduce((sum, op) => sum + (op.lineItems?.reduce((s, i) => s + i.amount, 0) || 0), 0);

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50 p-4 print:p-0 print:bg-white">
            <div className="relative w-full max-w-4xl">
                <div className="bg-white p-8 rounded-lg shadow-xl max-h-[90vh] overflow-y-auto text-gray-800 printable-area">
                    <header className="text-center mb-6 border-b-2 pb-4">
                         <h1 className="font-bold text-2xl">شركة إيجيبشن اكسبريس للشحن والتجارة</h1>
                         <h2 className="font-bold text-xl mt-2">كشف حساب عميل</h2>
                    </header>
                    <div className="grid grid-cols-2 gap-4 mb-6">
                        <div>
                            <p><span className="font-bold">العميل:</span> {client.name.replace('العملاء - ', '')}</p>
                            <p><span className="font-bold">العنوان:</span> {client.address || 'غير مسجل'}</p>
                        </div>
                        <div className="text-left">
                            <p><span className="font-bold">من تاريخ:</span> {new Date(fromDate).toLocaleDateString('ar-EG-u-nu-latn')}</p>
                            <p><span className="font-bold">إلى تاريخ:</span> {new Date(toDate).toLocaleDateString('ar-EG-u-nu-latn')}</p>
                        </div>
                    </div>

                    <table className="w-full text-right">
                        <thead className="bg-gray-100"><tr className="border-b-2 border-gray-300"><th className="p-2 font-semibold">التاريخ</th><th className="p-2 font-semibold">كود العملية</th><th className="p-2 font-semibold">البيان</th><th className="p-2 font-semibold text-center">المبلغ (مدين)</th></tr></thead>
                        <tbody>
                            {clientOperations.map(op => {
                                const revenue = op.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0;
                                return (
                                    <tr key={op.id} className="border-b border-gray-200"><td className="p-2">{new Date(op.creationDate).toLocaleDateString('ar-EG-u-nu-latn')}</td><td className="p-2 font-mono">{op.code}</td><td className="p-2">{op.description}</td><td className="p-2 text-center font-mono">{formatCurrency(revenue)}</td></tr>
                                );
                            })}
                        </tbody>
                        <tfoot><tr className="border-t-2 border-gray-300 bg-gray-100 font-bold"><td colSpan={3} className="p-2 text-left">الإجمالي (رصيد مدين)</td><td className="p-2 text-center font-mono">{formatCurrency(totalRevenue)}</td></tr></tfoot>
                    </table>
                </div>
                <div className="no-print absolute top-0 left-0 m-4 flex flex-col gap-2">
                    <button onClick={() => window.print()} className="px-4 py-2 bg-accent text-white rounded-lg shadow-lg hover:bg-accent-dark font-semibold">طباعة</button>
                    <button onClick={onClose} className="px-4 py-2 bg-gray-200 text-gray-800 rounded-lg shadow-lg hover:bg-gray-300 font-semibold">إغلاق</button>
                    <div className="bg-white p-2 rounded-lg shadow-lg">
                        <label className="text-sm font-semibold">من:</label><input type="date" value={fromDate} onChange={e => setFromDate(e.target.value)} className="w-full border p-1 rounded"/>
                        <label className="text-sm font-semibold mt-1">إلى:</label><input type="date" value={toDate} onChange={e => setToDate(e.target.value)} className="w-full border p-1 rounded"/>
                    </div>
                </div>
            </div>
        </div>
    );
};

// --- Operation Form Modal ---
interface OperationFormProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (operation: Operation | Omit<Operation, 'id'>) => void;
    initialData?: Operation | null;
    accounts: Account[];
    operations: Operation[];
    priceLists: PriceList[];
    setIsFormDirty: (isDirty: boolean) => void;
}

const BLANK_OPERATION_FORM: Omit<Operation, 'id' | 'code' | 'creationDate'> = {
    clientId: '', type: 'import', status: 'in-progress', description: '',
    billOfLading: '', containerNumber: '', voyageNumber: '', portOfLoading: '', portOfDischarge: '', lineItems: [], cost: 0
};

type OperationFormErrors = Partial<Record<keyof Operation, string>>;

const OperationForm: React.FC<OperationFormProps> = ({ isOpen, onClose, onSubmit, initialData, accounts, operations, priceLists, setIsFormDirty }) => {
    const [formData, setFormData] = useState<Omit<Operation, 'id'>>({ ...BLANK_OPERATION_FORM, code: '', creationDate: '' });
    const [hasChanged, setHasChanged] = useState(false);
    const [errors, setErrors] = useState<OperationFormErrors>({});

    const customerAccounts = useMemo(() => {
        return accounts
            .filter(acc => acc.accountCategory === 'Customer' || (acc.type === 'Asset' && acc.name.startsWith('العملاء')))
            .sort((a, b) => a.name.localeCompare(b.name));
    }, [accounts]);

    // Cleanup on unmount
    useEffect(() => {
        return () => setIsFormDirty(false);
    }, [setIsFormDirty]);

    useEffect(() => {
        setIsFormDirty(hasChanged);
    }, [hasChanged, setIsFormDirty]);

    useEffect(() => {
        if (isOpen) {
            setHasChanged(false);
            setErrors({});
            if (initialData) {
                const { id, ...dataToEdit } = initialData;
                setFormData({ 
                    ...dataToEdit, 
                    containerNumber: dataToEdit.containerNumber || '',
                    lineItems: dataToEdit.lineItems?.map(item => ({...item, taxType: item.taxType || 'none'})) || [],
                });
            } else {
                setFormData({
                    ...BLANK_OPERATION_FORM,
                    code: generateOperationCode('import', operations),
                    creationDate: new Date().toISOString().split('T')[0],
                    lineItems: [{ id: uuidv4(), description: '', amount: 0, taxType: 'none' }],
                });
            }
        } else {
            setHasChanged(false);
        }
    }, [initialData, isOpen, operations]);

    useEffect(() => {
        // Don't auto-apply on edit, only on new operations.
        // Also, don't run if there's no client selected.
        if (initialData || !formData.clientId || !isOpen) {
            // When editing, ensure line items have a default taxType if undefined
            if(initialData && formData.lineItems) {
                const needsUpdate = formData.lineItems.some(item => item.taxType === undefined);
                if(needsUpdate){
                    setFormData(prev => ({
                        ...prev,
                        lineItems: (prev.lineItems || []).map(item => ({...item, taxType: item.taxType || 'none'}))
                    }));
                }
            }
            return;
        };

        const customer = accounts.find(acc => acc.id === formData.clientId);

        // If a customer with a price list is selected
        if (customer && customer.priceListId) {
            const priceList = priceLists.find(pl => pl.id === customer.priceListId);
            if (priceList && priceList.items.length > 0) {
                // Check if the current line items are just the default empty one.
                const isPristine = (formData.lineItems?.length === 1 && !formData.lineItems[0].description && formData.lineItems[0].amount === 0);

                if (isPristine && window.confirm(`هذا العميل لديه قائمة أسعار افتراضية "${priceList.name}". هل تريد تطبيقها على هذه العملية؟`)) {
                    const newLineItems = priceList.items.map(item => ({
                        id: uuidv4(),
                        description: item.description,
                        amount: item.price,
                        taxType: item.taxType,
                        priceListItemId: item.id,
                        isPriceOverridden: false,
                    }));
                    setFormData(prev => ({ ...prev, lineItems: newLineItems }));
                    setHasChanged(true);
                }
            }
        }
    }, [formData.clientId, accounts, priceLists, initialData, isOpen]);

    const validate = (): boolean => {
        const newErrors: OperationFormErrors = {};
        if (!formData.code?.trim()) newErrors.code = "كود العملية مطلوب";
        if (!formData.creationDate) newErrors.creationDate = "تاريخ العملية مطلوب";
        if (!formData.clientId) newErrors.clientId = "يجب اختيار العميل";
        if (!formData.description?.trim()) newErrors.description = "وصف العملية مطلوب";

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        setHasChanged(true);
        const { name, value, type } = e.target;
        setFormData(prev => ({ ...prev, [name]: name === 'cost' ? parseFloat(value) || 0 : value }));

        // Clear error when user types
        if (errors[name as keyof Operation]) {
            setErrors(prev => ({ ...prev, [name]: undefined }));
        }
    };

    const handleLineChange = (id: string, field: keyof OperationLineItem, value: any) => {
        setHasChanged(true);
        setFormData(prev => ({
            ...prev,
            lineItems: (prev.lineItems || []).map(item => {
                if (item.id === id) {
                    const updatedItem = { ...item, [field]: value };
                    // If amount is changed and it came from a price list, mark as overridden
                    if (field === 'amount' && item.priceListItemId) {
                        updatedItem.isPriceOverridden = true;
                    }
                    return updatedItem;
                }
                return item;
            }),
        }));
    };

    const addLine = () => {
        setHasChanged(true);
        setFormData(prev => ({ ...prev, lineItems: [...(prev.lineItems || []), { id: uuidv4(), description: '', amount: 0, taxType: 'none' }] }));
    };

    const removeLine = (id: string) => {
        setHasChanged(true);
        setFormData(prev => ({ ...prev, lineItems: (prev.lineItems || []).filter(item => item.id !== id) }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();

        if (validate()) {
            if (initialData) { onSubmit({ ...initialData, ...formData }); } else { onSubmit(formData); }
            onClose();
        }
    };

    const handleCloseAttempt = () => {
        if (hasChanged) {
            if (window.confirm('لديك تغييرات غير محفوظة. هل أنت متأكد من رغبتك في الإغلاق؟')) {
                onClose();
            }
        } else {
            onClose();
        }
    };


    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50 p-4" onClick={handleCloseAttempt}>
            <div className="bg-primary p-8 rounded-2xl shadow-neumo w-full max-w-4xl max-h-full overflow-y-auto" onClick={e => e.stopPropagation()}>
                <h2 className="text-2xl font-bold mb-6 text-text-primary">{initialData ? 'تعديل عملية' : 'إضافة عملية جديدة'}</h2>
                <form onSubmit={handleSubmit}>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-x-6 gap-y-4">
                        <div className="md:col-span-3">
                            <label className="block text-text-secondary font-semibold mb-2">الوصف <span className="text-red-500">*</span></label>
                            <textarea 
                                name="description" 
                                value={formData.description} 
                                onChange={handleChange} 
                                rows={2} 
                                className={`w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm focus:outline-none focus:ring-2 focus:ring-accent text-text-primary ${errors.description ? 'border border-red-500 ring-1 ring-red-500' : ''}`} 
                            />
                            {errors.description && <p className="text-red-500 text-xs mt-1 flex items-center gap-1">{errors.description}</p>}
                        </div>
                        <div>
                            <label className="block text-text-secondary font-semibold mb-2">كود العملية <span className="text-red-500">*</span></label>
                            <input 
                                type="text" 
                                name="code" 
                                value={formData.code} 
                                onChange={handleChange} 
                                className={`w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary ${errors.code ? 'border border-red-500 ring-1 ring-red-500' : ''}`}
                            />
                            {errors.code && <p className="text-red-500 text-xs mt-1 flex items-center gap-1">{errors.code}</p>}
                        </div>
                        <div>
                            <label className="block text-text-secondary font-semibold mb-2">تاريخ الإنشاء <span className="text-red-500">*</span></label>
                            <input 
                                type="date" 
                                name="creationDate" 
                                value={formData.creationDate} 
                                onChange={handleChange} 
                                className={`w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary ${errors.creationDate ? 'border border-red-500 ring-1 ring-red-500' : ''}`}
                            />
                            {errors.creationDate && <p className="text-red-500 text-xs mt-1 flex items-center gap-1">{errors.creationDate}</p>}
                        </div>
                        <div>
                            <label className="block text-text-secondary font-semibold mb-2">العميل <span className="text-red-500">*</span></label>
                            <select 
                                name="clientId" 
                                value={formData.clientId} 
                                onChange={handleChange} 
                                className={`w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none text-text-primary ${errors.clientId ? 'border border-red-500 ring-1 ring-red-500' : ''}`}
                            >
                                <option value="">-- اختر عميل --</option>
                                {customerAccounts.map(acc => (
                                    <option key={acc.id} value={acc.id}>
                                        {acc.name.replace('العملاء - ', '')}
                                    </option>
                                ))}
                            </select>
                            {errors.clientId && <p className="text-red-500 text-xs mt-1 flex items-center gap-1">{errors.clientId}</p>}
                        </div>
                        <div>
                            <label className="block text-text-secondary font-semibold mb-2">نوع العملية</label>
                            <select name="type" value={formData.type} onChange={handleChange} className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none text-text-primary">
                                <option value="import">استيراد</option>
                                <option value="export">تصدير</option>
                                <option value="sea-clearance">تخليص بحري</option>
                                <option value="air-clearance">تخليص جوي</option>
                                <option value="return">مرتجع</option>
                                <option value="credit-note">إشعار دائن</option>
                            </select>
                        </div>
                        <div><label className="block text-text-secondary font-semibold mb-2">الحالة</label><select name="status" value={formData.status} onChange={handleChange} className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none text-text-primary"><option value="in-progress">قيد التنفيذ</option><option value="completed">مكتملة</option><option value="postponed">مؤجلة</option></select></div>
                        <div><label className="block text-text-secondary font-semibold mb-2">رقم بوليصة الشحن</label><input type="text" name="billOfLading" value={formData.billOfLading} onChange={handleChange} className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary" /></div>
                        <div><label className="block text-text-secondary font-semibold mb-2">رقم الحاوية</label><input type="text" name="containerNumber" value={formData.containerNumber} onChange={handleChange} className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary" /></div>
                        <div><label className="block text-text-secondary font-semibold mb-2">رقم الرحلة</label><input type="text" name="voyageNumber" value={formData.voyageNumber} onChange={handleChange} className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary" /></div>
                        <div><label className="block text-text-secondary font-semibold mb-2">ميناء الشحن</label><input type="text" name="portOfLoading" value={formData.portOfLoading || ''} onChange={handleChange} className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary" /></div>
                        <div><label className="block text-text-secondary font-semibold mb-2">ميناء الوصول</label><input type="text" name="portOfDischarge" value={formData.portOfDischarge || ''} onChange={handleChange} className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary" /></div>
                    </div>

                    <div className="md:col-span-3 mt-6">
                        <h3 className="text-lg font-bold text-text-primary mb-2 border-t pt-4 border-primary-dark/20">بنود الفاتورة</h3>
                        <div className="space-y-2">
                        {(formData.lineItems || []).map((item, index) => (
                            <div key={item.id} className="grid grid-cols-[1fr_150px_180px_auto] gap-2 items-center">
                                <input type="text" value={item.description} onChange={e => handleLineChange(item.id, 'description', e.target.value)} placeholder="وصف البند" className="p-2 bg-primary rounded-lg shadow-neumo-inset-sm text-text-primary" />
                                <div className="relative">
                                    <input type="number" value={item.amount} onChange={e => handleLineChange(item.id, 'amount', parseFloat(e.target.value) || 0)} placeholder="المبلغ" className="w-full p-2 bg-primary rounded-lg shadow-neumo-inset-sm text-text-primary" />
                                    {item.isPriceOverridden && <span title="تم تعديل السعر الأصلي" className="absolute left-2 top-1/2 -translate-y-1/2 text-amber-500 font-bold text-lg">*</span>}
                                </div>
                                <select 
                                    value={item.taxType || 'none'} 
                                    onChange={e => handleLineChange(item.id, 'taxType', e.target.value as TaxType)}
                                    className="p-2 bg-primary rounded-lg shadow-neumo-inset-sm appearance-none focus:outline-none focus:ring-1 focus:ring-accent text-text-primary"
                                >
                                    <option value="none">بدون ضريبة</option>
                                    <option value="schedule">ضريبة جدول (10%)</option>
                                    <option value="vat">ضريبة قيمة مضافة (14%)</option>
                                </select>
                                <button type="button" onClick={() => removeLine(item.id)} className="text-red-500"><MinusCircle size={18} /></button>
                            </div>
                        ))}
                        </div>
                        <button type="button" onClick={addLine} className="mt-2 flex items-center gap-2 text-accent font-semibold"><PlusCircle size={18} /> إضافة بند</button>
                    </div>

                    <div className="mt-8 flex justify-end gap-4"><button type="button" onClick={handleCloseAttempt} className="px-6 py-2 bg-primary text-text-primary rounded-xl hover:shadow-neumo-inset shadow-neumo-sm font-semibold">إلغاء</button><button type="submit" className="px-6 py-2 bg-accent text-white rounded-md hover:bg-accent-dark font-semibold">حفظ</button></div>
                </form>
            </div>
        </div>
    );
};

// --- Main Operations Component ---
interface OperationsProps {
    operations: Operation[];
    accounts: Account[];
    journalEntries: JournalEntry[];
    documents: Document[];
    addOperation: (operation: Omit<Operation, 'id'>) => void;
    updateOperation: (operation: Operation) => void;
    deleteOperation: (id: string) => void;
    linkOperationToJournalEntry: (operationId: string, journalEntryId: string) => void;
    currentUser: User;
    setIsFormDirty: (isDirty: boolean) => void;
    onNavigateToJournal: (view: string) => void;
    priceLists: PriceList[];
    addDocument: (file: File, linkedToId: string, linkedToType: 'account' | 'operation') => Promise<void>;
    deleteDocument: (id: string) => void;
    linkExistingDocuments: (documentsToLink: Document[], linkedToId: string, linkedToType: 'account' | 'operation') => void;
    initialOperationId?: string | null;
    onClearInitialOperation?: () => void;
}

const Operations: React.FC<OperationsProps> = ({ operations, accounts, journalEntries, documents, addOperation, updateOperation, deleteOperation, linkOperationToJournalEntry, currentUser, setIsFormDirty, onNavigateToJournal, priceLists, addDocument, deleteDocument, linkExistingDocuments, initialOperationId, onClearInitialOperation }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [currentOperation, setCurrentOperation] = useState<Operation | null>(null);
    const [viewingDocument, setViewingDocument] = useState<{ type: 'invoice' | 'statement', operation?: Operation, client?: Account } | null>(null);
    const [viewingOperation, setViewingOperation] = useState<Operation | null>(null); // State for read-only view

    // Virtualization / Infinite Scroll State
    const [visibleCount, setVisibleCount] = useState(20);
    const observer = useRef<IntersectionObserver | null>(null);

    const [searchQuery, setSearchQuery] = useState('');
    const [filterType, setFilterType] = useState<OperationType | 'all'>(() => (localStorage.getItem('operationsFilterType') as any) || 'all');
    const [filterStatus, setFilterStatus] = useState<OperationStatus | 'all'>(() => (localStorage.getItem('operationsFilterStatus') as any) || 'all');
    const [filterClient, setFilterClient] = useState<string>(() => (localStorage.getItem('operationsFilterClient') as string) || 'all');
    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' }>({ key: 'date', direction: 'desc' });

    const [isLinkModalOpen, setIsLinkModalOpen] = useState(false);
    const [operationToLink, setOperationToLink] = useState<Operation | null>(null);


    const canCreate = canPerformAction(currentUser.role, 'create');
    const canEdit = canPerformAction(currentUser.role, 'edit');
    const canDelete = canPerformAction(currentUser.role, 'delete');

    useEffect(() => { localStorage.setItem('operationsFilterType', filterType); }, [filterType]);
    useEffect(() => { localStorage.setItem('operationsFilterStatus', filterStatus); }, [filterStatus]);
    useEffect(() => { localStorage.setItem('operationsFilterClient', filterClient); }, [filterClient]);

    // Effect to handle deep linking to a specific operation
    useEffect(() => {
        if (initialOperationId) {
            const op = operations.find(o => o.id === initialOperationId);
            if (op) {
                setViewingOperation(op);
                // Clear the initial ID to prevent reopening on subsequent renders
                if (onClearInitialOperation) onClearInitialOperation();
            }
        }
    }, [initialOperationId, operations, onClearInitialOperation]);

    const handleAddNew = () => { if(canCreate) { setCurrentOperation(null); setIsModalOpen(true); } };
    const handleEdit = (operation: Operation) => { if(canEdit) { setCurrentOperation(operation); setIsModalOpen(true); } };
    const handleSubmit = (operationData: Operation | Omit<Operation, 'id'>) => { 'id' in operationData ? updateOperation(operationData) : addOperation(operationData); };

    const handleOpenInvoice = (operation: Operation) => {
        const client = accounts.find(acc => acc.id === operation.clientId);
        if(client) setViewingDocument({ type: 'invoice', operation, client });
    };

    const handleOpenStatement = () => {
        const clientId = prompt("أدخل كود العميل لعرض كشف الحساب:", "1210");
        if(clientId) {
            const client = accounts.find(acc => acc.id === clientId);
            if(client) {
                setViewingDocument({ type: 'statement', client });
            } else {
                alert("لم يتم العثور على العميل.");
            }
        }
    };

    const handleSort = (key: string) => {
        setSortConfig(current => ({
            key,
            direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const getClientName = (id: string) => accounts.find(a => a.id === id)?.name.replace('العملاء - ', '') || 'غير معروف';

    const filteredOperations = useMemo(() => {
        let result = operations
            .filter(op => filterType === 'all' || op.type === filterType)
            .filter(op => filterStatus === 'all' || op.status === filterStatus)
            .filter(op => filterClient === 'all' || op.clientId === filterClient);

        if (searchQuery) {
            const query = searchQuery.toLowerCase();
            result = result.filter(op => 
                op.code.toLowerCase().includes(query) ||
                op.description.toLowerCase().includes(query) ||
                (op.billOfLading && op.billOfLading.toLowerCase().includes(query)) ||
                (op.containerNumber && op.containerNumber.toLowerCase().includes(query))
            );
        }

        return result.sort((a, b) => {
            let comparison = 0;
            switch (sortConfig.key) {
                case 'code':
                    comparison = a.code.localeCompare(b.code);
                    break;
                case 'client':
                    comparison = getClientName(a.clientId).localeCompare(getClientName(b.clientId));
                    break;
                case 'revenue':
                    const revA = a.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0;
                    const revB = b.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0;
                    comparison = revA - revB;
                    break;
                case 'cost':
                    comparison = (a.cost || 0) - (b.cost || 0);
                    break;
                case 'profit':
                    const profitA = (a.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0) - (a.cost || 0);
                    const profitB = (b.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0) - (b.cost || 0);
                    comparison = profitA - profitB;
                    break;
                case 'date':
                default:
                    comparison = new Date(a.creationDate).getTime() - new Date(b.creationDate).getTime();
                    break;
            }
            return sortConfig.direction === 'asc' ? comparison : -comparison;
        });
    }, [operations, filterType, filterStatus, filterClient, searchQuery, sortConfig, accounts]);

    // Reset visible count when filters change to start from top
    useEffect(() => {
        setVisibleCount(20);
    }, [filteredOperations]);

    const lastOperationElementRef = useCallback((node: HTMLTableRowElement) => {
        if (observer.current) observer.current.disconnect();
        observer.current = new IntersectionObserver(entries => {
            if (entries[0].isIntersecting && visibleCount < filteredOperations.length) {
                setVisibleCount(prev => prev + 20);
            }
        });
        if (node) observer.current.observe(node);
    }, [visibleCount, filteredOperations.length]);

    const totals = useMemo(() => {
        return filteredOperations.reduce((acc, op) => {
            const totalRevenue = op.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0;
            const cost = op.cost || 0;
            const profit = totalRevenue - cost;

            acc.totalRevenue += totalRevenue;
            acc.totalCost += cost;
            acc.totalProfit += profit;
            return acc;
        }, { totalRevenue: 0, totalCost: 0, totalProfit: 0 });
    }, [filteredOperations]);


    const csvDataForExport = useMemo(() => {
        const headers = ["الكود", "التاريخ", "العميل", "النوع", "الحالة", "الإيراد", "التكلفة", "الربح", "الوصف"];
        const data = filteredOperations.map(op => {
            const client = accounts.find(acc => acc.id === op.clientId);
            const totalRevenue = op.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0;
            const profit = totalRevenue - (op.cost || 0);
            return [
                op.code,
                op.creationDate,
                client?.name.replace('العملاء - ', '') || 'غير معروف',
                typeMap[op.type],
                statusMap[op.status].text,
                totalRevenue,
                op.cost || 0,
                profit,
                op.description
            ];
        });
        return { headers, data };
    }, [filteredOperations, accounts]);

    const emailBody = `ملخص العمليات\n\nيحتوي هذا التقرير على ${filteredOperations.length} عملية حسب الفلتر المطبق.`;

    const customerAccounts = useMemo(() => {
        return accounts
            .filter(acc => acc.accountCategory === 'Customer' || (acc.type === 'Asset' && acc.name.startsWith('العملاء')))
            .sort((a, b) => a.name.localeCompare(b.name));
    }, [accounts]);

    const SortIcon = ({ column }: { column: string }) => {
        if (sortConfig.key !== column) return null;
        return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="inline ml-1" /> : <ArrowDown size={14} className="inline ml-1" />;
    };

    const displayedOperations = filteredOperations.slice(0, visibleCount);

    return (
        <div className="space-y-8">
            <OperationForm isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSubmit={handleSubmit} initialData={currentOperation} accounts={accounts} operations={operations} setIsFormDirty={setIsFormDirty} priceLists={priceLists} />

            <LinkJournalEntryModal
                isOpen={isLinkModalOpen}
                onClose={() => setIsLinkModalOpen(false)}
                operationToLink={operationToLink}
                journalEntries={journalEntries}
                operations={operations}
                onLink={(opId, jeId) => {
                    linkOperationToJournalEntry(opId, jeId);
                    setIsLinkModalOpen(false);
                }}
            />

            {viewingOperation && (
                <OperationDetailView 
                    operation={viewingOperation}
                    client={accounts.find(acc => acc.id === viewingOperation.clientId)!}
                    onClose={() => setViewingOperation(null)}
                    onNavigateToJournal={onNavigateToJournal}
                    documents={documents.filter(d => d.linkedToId === viewingOperation.id && d.linkedToType === 'operation')}
                    allDocuments={documents}
                    addDocument={addDocument}
                    deleteDocument={deleteDocument}
                    linkExistingDocuments={linkExistingDocuments}
                    currentUser={currentUser}
                />
            )}

            <div className="bg-primary p-6 rounded-2xl shadow-neumo printable-area">
                 <div className="flex items-center justify-between gap-4 mb-4 flex-wrap no-print">
                     <div className="flex items-center gap-4 flex-wrap">
                        <div className="relative">
                            <input 
                                type="text" 
                                placeholder="بحث بالكود أو الوصف..." 
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-48 p-2 pr-8 bg-primary rounded-xl shadow-neumo-inset-sm focus:outline-none focus:ring-1 focus:ring-accent text-sm text-text-primary"
                            />
                            <Search size={16} className="absolute right-2 top-1/2 -translate-y-1/2 text-text-secondary" />
                        </div>
                        <div className="flex items-center gap-2">
                             <label htmlFor="filterClient" className="font-semibold text-text-secondary text-sm">العميل:</label>
                             <select id="filterClient" value={filterClient} onChange={e => setFilterClient(e.target.value)} className="p-2 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none focus:outline-none focus:ring-1 focus:ring-accent max-w-48 text-sm text-text-primary">
                                <option value="all">كل العملاء</option>
                                {customerAccounts.map(client => <option key={client.id} value={client.id}>{client.name.replace('العملاء - ', '')}</option>)}
                             </select>
                        </div>
                        <div className="flex items-center gap-2">
                             <label htmlFor="filterType" className="font-semibold text-text-secondary text-sm">النوع:</label>
                             <select id="filterType" value={filterType} onChange={e => setFilterType(e.target.value as any)} className="p-2 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none focus:outline-none focus:ring-1 focus:ring-accent text-sm text-text-primary">
                                <option value="all">كل الأنواع</option>
                                {Object.entries(typeMap).map(([key, value]) => <option key={key} value={key}>{value}</option>)}
                             </select>
                        </div>
                        <div className="flex items-center gap-2">
                             <label htmlFor="filterStatus" className="font-semibold text-text-secondary text-sm">الحالة:</label>
                             <select id="filterStatus" value={filterStatus} onChange={e => setFilterStatus(e.target.value as any)} className="p-2 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none focus:outline-none focus:ring-1 focus:ring-accent text-sm text-text-primary">
                                <option value="all">كل الحالات</option>
                                {Object.entries(statusMap).map(([key, value]) => <option key={key} value={key}>{value.text}</option>)}
                             </select>
                        </div>
                        {(filterType !== 'all' || filterStatus !== 'all' || filterClient !== 'all' || searchQuery) && (
                            <button 
                                onClick={() => { setFilterType('all'); setFilterStatus('all'); setFilterClient('all'); setSearchQuery(''); }} 
                                className="flex items-center gap-1 px-3 py-2 text-sm bg-primary text-accent rounded-xl hover:shadow-neumo-inset shadow-neumo-sm font-semibold"
                            >
                                <X size={16} />
                                مسح
                            </button>
                        )}
                    </div>
                    <div className="flex gap-2">
                         <ExportDropdown
                            title={`تقرير_العمليات`}
                            csvHeaders={csvDataForExport.headers}
                            csvData={csvDataForExport.data}
                            emailBodyContent={emailBody}
                            onPrint={() => window.print()}
                        />
                        <button onClick={handleOpenStatement} className="flex items-center gap-2 px-4 py-2 bg-primary text-text-primary rounded-xl hover:shadow-neumo-inset shadow-neumo-sm font-semibold text-sm"><UserIcon size={18}/> كشف حساب</button>
                        {canCreate && <button onClick={handleAddNew} className="flex items-center gap-2 px-4 py-2 bg-accent text-white rounded-md hover:bg-accent-dark font-semibold shadow-sm text-sm"><PlusCircle size={20} /> إضافة عملية</button>}
                    </div>
                </div>
                <div className="text-sm text-text-secondary mb-2 no-print">
                    {`عرض ${displayedOperations.length} من إجمالي ${filteredOperations.length} عملية.`}
                </div>
                <div className="overflow-x-auto max-h-[70vh]">
                    <table className="w-full text-right border-separate border-spacing-0">
                        <thead className="bg-primary-light uppercase text-sm text-text-secondary font-bold sticky top-0 z-10 shadow-sm">
                            <tr>
                                <th className="p-4 cursor-pointer hover:text-text-primary transition-colors" onClick={() => handleSort('code')}>كود العملية / الوصف <SortIcon column="code"/></th>
                                <th className="p-4 cursor-pointer hover:text-text-primary transition-colors" onClick={() => handleSort('date')}>التاريخ <SortIcon column="date"/></th>
                                <th className="p-4 cursor-pointer hover:text-text-primary transition-colors" onClick={() => handleSort('client')}>العميل <SortIcon column="client"/></th>
                                <th className="p-4">النوع</th>
                                <th className="p-4 text-center">الحالة</th>
                                <th className="p-4 text-center cursor-pointer hover:text-text-primary transition-colors" onClick={() => handleSort('revenue')}>الإيراد <SortIcon column="revenue"/></th>
                                <th className="p-4 text-center cursor-pointer hover:text-text-primary transition-colors" onClick={() => handleSort('cost')}>التكلفة <SortIcon column="cost"/></th>
                                <th className="p-4 text-center cursor-pointer hover:text-text-primary transition-colors" onClick={() => handleSort('profit')}>الربح <SortIcon column="profit"/></th>
                                <th className="p-4 no-print text-center">إجراءات</th>
                            </tr>
                        </thead>
                        <tbody>
                            {displayedOperations.map((op, index) => {
                                const client = accounts.find(acc => acc.id === op.clientId);
                                const totalRevenue = op.lineItems?.reduce((sum, item) => sum + item.amount, 0) || 0;
                                const profit = totalRevenue - (op.cost || 0);
                                const hasAttachment = documents.some(doc => doc.linkedToId === op.id);
                                const isLast = index === displayedOperations.length - 1;

                                return (
                                <tr 
                                    key={op.id} 
                                    ref={isLast ? lastOperationElementRef : null}
                                    className="border-b border-primary-dark/10 hover:bg-primary-dark/5 cursor-pointer transition-colors even:bg-primary-dark/5" 
                                    onClick={() => setViewingOperation(op)}
                                >
                                    <td className="p-4">
                                        <div className="flex items-center gap-2 mb-1">
                                            <span className="font-extrabold text-lg text-text-primary whitespace-nowrap">{op.code}</span>
                                            {hasAttachment && <Paperclip size={14} className="text-text-secondary" />}
                                        </div>
                                        <div className="text-xs text-text-secondary truncate max-w-[200px]" title={op.description}>{op.description}</div>
                                    </td>
                                    <td className="p-4 whitespace-nowrap text-sm font-medium text-text-primary">
                                        <div className="flex items-center gap-2">
                                            <Calendar size={14} />
                                            {new Date(op.creationDate).toLocaleDateString('ar-EG-u-nu-latn')}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <div className="flex items-center gap-2 font-semibold text-text-primary">
                                            <Building2 size={16} className="text-text-secondary" />
                                            {client?.name.replace('العملاء - ', '') || 'غير معروف'}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <div className="flex items-center gap-2 text-sm font-medium text-text-secondary">
                                            {getOperationTypeIcon(op.type)}
                                            <span>{typeMap[op.type]}</span>
                                        </div>
                                    </td>
                                    <td className="p-4 text-center">
                                        <div className="flex flex-col items-center gap-1">
                                            <span className={`px-3 py-1 text-xs font-bold rounded-full border ${statusMap[op.status].className}`}>
                                                {statusMap[op.status].text}
                                            </span>
                                            {op.journalEntryId && <div className="flex items-center gap-1 text-[10px] text-green-600 font-bold"><Book size={10}/> مرتبط</div>}
                                        </div>
                                    </td>
                                    <td className="p-4 text-center font-mono text-text-primary font-medium whitespace-nowrap">{formatCurrency(totalRevenue)}</td>
                                    <td className="p-4 text-center font-mono text-red-600 font-medium whitespace-nowrap">({formatCurrency(op.cost)})</td>
                                    <td className={`p-4 text-center font-mono font-bold whitespace-nowrap ${profit >= 0 ? 'text-green-600' : 'text-red-600'}`}>{formatCurrency(profit)}</td>
                                    <td className="p-4 no-print">
                                        <div className="flex justify-center gap-2" onClick={e => e.stopPropagation()}>
                                            {!op.journalEntryId && canEdit && (
                                                <button onClick={(e) => { e.stopPropagation(); setOperationToLink(op); setIsLinkModalOpen(true); }} className="p-2 text-blue-500 bg-blue-50 rounded-full hover:bg-blue-100" title="ربط بقيد يومية">
                                                    <Link size={16} />
                                                </button>
                                            )}
                                            {canEdit && <button onClick={() => handleEdit(op)} className="p-2 text-accent bg-blue-50 rounded-full hover:bg-blue-100" title="تعديل"><Edit size={16} /></button>}
                                            <button onClick={() => handleOpenInvoice(op)} className="p-2 text-gray-600 bg-gray-100 rounded-full hover:bg-gray-200" title="إصدار فاتورة"><FileText size={16} /></button>
                                            {canDelete && <button onClick={() => deleteOperation(op.id)} className="p-2 text-red-500 bg-red-50 rounded-full hover:bg-red-100" title="حذف"><Trash2 size={16} /></button>}
                                        </div>
                                    </td>
                                </tr>
                            )})}
                        </tbody>
                        <tfoot className="sticky bottom-0 z-10 bg-primary-light shadow-[0_-2px_4px_rgba(0,0,0,0.05)]">
                            <tr className="font-extrabold border-t-2 border-primary-dark/30">
                                <td className="p-4" colSpan={5}>الإجمالي</td>
                                <td className="p-4 text-center font-mono text-text-primary">{formatCurrency(totals.totalRevenue)}</td>
                                <td className="p-4 text-center font-mono text-red-600">({formatCurrency(totals.totalCost)})</td>
                                <td className={`p-4 text-center font-mono ${totals.totalProfit >= 0 ? 'text-green-600' : 'text-red-600'}`}>{formatCurrency(totals.totalProfit)}</td>
                                <td className="p-4 no-print"></td>
                            </tr>
                        </tfoot>
                    </table>
                     {filteredOperations.length === 0 && <p className="text-center text-text-secondary p-8">لا توجد عمليات تطابق الفلتر الحالي.</p>}
                </div>
            </div>

            {viewingDocument?.type === 'invoice' && viewingDocument.operation && viewingDocument.client && (
              <Invoice operation={viewingDocument.operation} client={viewingDocument.client} onClose={() => setViewingDocument(null)} />
            )}
            {viewingDocument?.type === 'statement' && viewingDocument.client && (
                <AccountStatement client={viewingDocument.client} operations={operations} onClose={() => setViewingDocument(null)} />
            )}
        </div>
    );
};

export default Operations;

import React, { useState, useMemo, useEffect } from 'react';
import { JournalEntry, JournalEntryLine, Account, TransactionType, User, Document, PriceList, Operation } from '../types.ts';
import { Plus, X, Printer, AlertTriangle, ArrowRight, Receipt, Filter, XCircle, Globe, ChevronDown, CreditCard, Search, Ship } from 'lucide-react';
import { canPerformAction } from '../permissions.ts';
import AccountLedger from './AccountLedger.tsx';
import Voucher from './Voucher.tsx';
import { AccountDetailView } from './AccountDetailView.tsx';


interface JournalProps {
  journalEntries: JournalEntry[];
  addJournalEntry: (entry: Omit<JournalEntry, 'id'>, options?: { suppressSuggestion?: boolean }) => Promise<string>;
  accounts: Account[];
  currentUser: User;
  setIsFormDirty: (isDirty: boolean) => void;
  prefilledJournalLine: Partial<JournalEntryLine> | null;
  clearPrefill: () => void;
  onAccountClick: (account: Account) => void; // New prop for navigation
  operations: Operation[];
  onNavigateToOperation: (operation: Operation) => void;
}

const NewEntryForm: React.FC<{ addJournalEntry: (entry: Omit<JournalEntry, 'id'>, options?: { suppressSuggestion?: boolean }) => Promise<string>; accounts: Account[]; journalEntries: JournalEntry[]; setIsFormDirty: (isDirty: boolean) => void; prefilledJournalLine: Partial<JournalEntryLine> | null; clearPrefill: () => void; }> = ({ addJournalEntry, accounts, journalEntries, setIsFormDirty, prefilledJournalLine, clearPrefill }) => {
    // Common fields
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [description, setDescription] = useState('');
    const [referenceNumber, setReferenceNumber] = useState('');
    const [transactionType, setTransactionType] = useState<TransactionType>('general');
    const [error, setError] = useState('');
    const [hasChanged, setHasChanged] = useState(false);

    // State for General Entry
    const [lines, setLines] = useState<Partial<JournalEntryLine>[]>([
        { accountId: '', debit: 0, credit: 0, amountForeign: 0, currency: 'EGP', conversionRate: 1 },
        { accountId: '', debit: 0, credit: 0, amountForeign: 0, currency: 'EGP', conversionRate: 1 },
    ]);

    // State for Simplified Entries
    const [amount, setAmount] = useState<number>(0);
    const [fromAccountId, setFromAccountId] = useState('');
    const [toAccountId, setToAccountId] = useState('');
    const [isForeignCurrency, setIsForeignCurrency] = useState(false);
    const [foreignCurrency, setForeignCurrency] = useState('USD');
    const [conversionRate, setConversionRate] = useState(1);

    // State for Check Details
    const [showCheckDetails, setShowCheckDetails] = useState(false);
    const [checkNumber, setCheckNumber] = useState('');
    const [checkDate, setCheckDate] = useState(new Date().toISOString().split('T')[0]);


    useEffect(() => {
        setIsFormDirty(hasChanged);
        // Cleanup: Reset dirty state when component unmounts or navigation happens
        return () => setIsFormDirty(false);
    }, [hasChanged, setIsFormDirty]);

     useEffect(() => {
        if (prefilledJournalLine) {
            setTransactionType('general'); // Force general entry for flexibility
            setLines(prevLines => {
                const newLines = [...prevLines];
                newLines[0] = { ...newLines[0], ...prefilledJournalLine }; 
                return newLines;
            });
            setHasChanged(true);
            clearPrefill(); 
        }
    }, [prefilledJournalLine, clearPrefill]);

    // Filtered account lists for simplified forms
    const customerAccounts = accounts.filter(acc => acc.type === 'Asset' && acc.name.startsWith('العملاء'));
    const cashAndBankAccounts = accounts.filter(acc => acc.isBankOrCash);
    const payableToAccounts = accounts.filter(acc => ['Asset', 'Liability', 'Expense'].includes(acc.type) && !acc.isBankOrCash);

    // Auto-detect if a simplified transaction should be foreign currency
    useEffect(() => {
        const fromAccount = accounts.find(a => a.id === fromAccountId);
        const toAccount = accounts.find(a => a.id === toAccountId);
        const foreignAccount = transactionType === 'receipt' ? toAccount : fromAccount; // The cash/bank account determines currency

        if (foreignAccount?.currencyType === 'foreign' && foreignAccount.currency) {
            setIsForeignCurrency(true);
            setForeignCurrency(foreignAccount.currency);
            setConversionRate(foreignAccount.conversionRate || 1);
        } else {
            setIsForeignCurrency(false);
            setForeignCurrency('USD');
            setConversionRate(1);
        }
    }, [fromAccountId, toAccountId, transactionType, accounts]);

    // Show/Hide check details based on transaction type and account selection
    useEffect(() => {
        const fromAccount = accounts.find(a => a.id === fromAccountId);
        const toAccount = accounts.find(a => a.id === toAccountId);
        const isBankTransaction = fromAccount?.category === 'bank' || toAccount?.category === 'bank';
        const isPaymentOrReceipt = transactionType === 'payment' || transactionType === 'receipt';

        setShowCheckDetails(isBankTransaction && isPaymentOrReceipt);
    }, [fromAccountId, toAccountId, transactionType, accounts]);

    // Check sequence suggestion logic
    useEffect(() => {
        // Only suggest for 'payment' from a bank account
        if (transactionType === 'payment' && fromAccountId) {
            const fromAccount = accounts.find(a => a.id === fromAccountId);
            if (fromAccount?.category === 'bank') {
                const latestCheckEntry = journalEntries
                    .filter(je => 
                        je.transactionType === 'payment' &&
                        je.lines.some(l => l.accountId === fromAccountId && l.credit > 0) &&
                        je.checkDetails?.checkNumber
                    )
                    .sort((a, b) => {
                        if (a.date > b.date) return -1;
                        if (a.date < b.date) return 1;
                        const numA = parseInt(a.checkDetails!.checkNumber!, 10);
                        const numB = parseInt(b.checkDetails!.checkNumber!, 10);
                        if (!isNaN(numA) && !isNaN(numB)) {
                            return numB - numA;
                        }
                        return 0;
                    })[0];

                if (latestCheckEntry && latestCheckEntry.checkDetails?.checkNumber) {
                    const lastCheckNum = parseInt(latestCheckEntry.checkDetails.checkNumber, 10);
                    if (!isNaN(lastCheckNum)) {
                        const nextCheckNumStr = (lastCheckNum + 1).toString();
                        const originalLength = latestCheckEntry.checkDetails.checkNumber.length;
                        if (originalLength > nextCheckNumStr.length) {
                             setCheckNumber(nextCheckNumStr.padStart(originalLength, '0'));
                        } else {
                            setCheckNumber(nextCheckNumStr);
                        }
                    }
                } else {
                    setCheckNumber('');
                }
            } else {
                setCheckNumber('');
            }
        } else {
            setCheckNumber('');
        }
    }, [fromAccountId, transactionType, accounts, journalEntries]);


    // EFFECT TO AUTO-SELECT 'FROM' ACCOUNT BASED ON LINK
    useEffect(() => {
        if (transactionType === 'payment' && toAccountId) {
            const targetAccount = accounts.find(acc => acc.id === toAccountId);
            if (targetAccount?.linkedAccountId) {
                // Check if the linked account is a valid "from" account
                if (cashAndBankAccounts.some(c => c.id === targetAccount.linkedAccountId)) {
                    setFromAccountId(targetAccount.linkedAccountId);
                    setHasChanged(true);
                }
            }
        }
    }, [toAccountId, transactionType, accounts, cashAndBankAccounts]);


    const resetAllForms = () => {
        setDate(new Date().toISOString().split('T')[0]);
        setDescription('');
        setReferenceNumber('');
        setError('');
        // Reset general
        setLines([
            { accountId: '', debit: 0, credit: 0, amountForeign: 0, currency: 'EGP', conversionRate: 1 },
            { accountId: '', debit: 0, credit: 0, amountForeign: 0, currency: 'EGP', conversionRate: 1 },
        ]);
        // Reset simplified
        setAmount(0);
        setFromAccountId('');
        setToAccountId('');
        setIsForeignCurrency(false);
        setForeignCurrency('USD');
        setConversionRate(1);
        // Reset check details
        setCheckNumber('');
        setCheckDate(new Date().toISOString().split('T')[0]);
        setShowCheckDetails(false);
        setHasChanged(false);
    };

    const handleTransactionTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        resetAllForms(); // Reset forms when type changes
        setTransactionType(e.target.value as TransactionType);
        // Do not set dirty immediately on type change to prevent navigation lock if user changes mind immediately
        // setHasChanged(true); 
    };


    const handleLineChange = (index: number, field: keyof JournalEntryLine | 'debitForeign' | 'creditForeign', value: string | number) => {
        setHasChanged(true);
        const newLines = [...lines];
        let line = { ...newLines[index] };

        // Auto-set currency when account is selected
        if (field === 'accountId') {
            line.accountId = value as string;
            const account = accounts.find(a => a.id === value);
            if (account?.currency && account.currency !== 'EGP') {
                line.currency = account.currency;
                line.conversionRate = account.conversionRate || 1;
            } else {
                line.currency = 'EGP';
                line.conversionRate = 1;
                 // When EGP is selected, the foreign amount should match the egyptian amount
                if (line.debit! > 0) line.amountForeign = line.debit;
                else if (line.credit! > 0) line.amountForeign = line.credit;
            }
        }

        const numValue = Number(value) || 0;
        const isForeign = line.currency !== 'EGP';
        const rate = Number(line.conversionRate) || 1;

        if (field === 'debitForeign') {
            line.amountForeign = numValue;
            line.debit = isForeign ? numValue * rate : numValue;
            line.credit = 0;
        } else if (field === 'creditForeign') {
            line.amountForeign = numValue;
            line.credit = isForeign ? numValue * rate : numValue;
            line.debit = 0;
        } else if (field === 'conversionRate') {
            line.conversionRate = numValue;
             if (line.debit! > 0) {
                 line.debit = (line.amountForeign || 0) * numValue;
             }
             else if (line.credit! > 0) {
                 line.credit = (line.amountForeign || 0) * numValue;
             }
        } else if (field === 'currency') {
             line.currency = value as string;
             if (value === 'EGP') {
                line.conversionRate = 1;
                 if (line.amountForeign) {
                    if (line.debit! > 0) line.debit = line.amountForeign;
                    if (line.credit! > 0) line.credit = line.amountForeign;
                 }
                line.amountForeign = undefined;
             }
        } else {
            line = { ...line, [field as keyof JournalEntryLine]: value };
        }

        newLines[index] = line;
        setLines(newLines);
    };

    const addLine = () => {
        setHasChanged(true);
        setLines([...lines, { accountId: '', debit: 0, credit: 0, amountForeign: 0, currency: 'EGP', conversionRate: 1 }]);
    };

    const removeLine = (index: number) => {
        if (lines.length > 2) {
            setHasChanged(true);
            const newLines = lines.filter((_, i) => i !== index);
            setLines(newLines);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        if (!description.trim()) {
            setError('الرجاء إدخال وصف للحركة.');
            return;
        }

        let finalLines: JournalEntryLine[] = [];

        if (transactionType === 'receipt' || transactionType === 'payment') {
            if (!amount || amount <= 0) { setError('الرجاء إدخال مبلغ صحيح وأكبر من صفر.'); return; }
            if (!fromAccountId || !toAccountId) { setError('الرجاء تحديد الحسابات.'); return; }
            if (isForeignCurrency && (!conversionRate || conversionRate <= 0)) { setError('الرجاء إدخال سعر صرف صحيح.'); return; }

            const egpAmount = isForeignCurrency ? amount * conversionRate : amount;

            const baseProps = isForeignCurrency ? { amountForeign: amount, currency: foreignCurrency, conversionRate } : {};

            if (transactionType === 'receipt') {
                finalLines = [
                    { accountId: toAccountId, debit: egpAmount, credit: 0, ...baseProps },
                    { accountId: fromAccountId, debit: 0, credit: egpAmount, ...baseProps },
                ];
            } else { // payment
                finalLines = [
                    { accountId: toAccountId, debit: egpAmount, credit: 0, ...baseProps },
                    { accountId: fromAccountId, debit: 0, credit: egpAmount, ...baseProps },
                ];
            }
        } else { // 'general'
            const totalDebit = lines.reduce((sum, line) => sum + (line.debit || 0), 0);
            const totalCredit = lines.reduce((sum, line) => sum + (line.credit || 0), 0);

            if (Math.abs(totalDebit - totalCredit) > 0.01) { 
                setError(`القيد غير متوازن. إجمالي المدين (${totalDebit.toFixed(2)}) لا يساوي إجمالي الدائن (${totalCredit.toFixed(2)}). الفرق: ${(totalDebit - totalCredit).toFixed(2)}`); 
                return; 
            }
            if (totalDebit === 0) { setError('لا يمكن أن يكون إجمالي القيد صفراً.'); return; }

            finalLines = lines.filter(line => line.accountId && (line.debit || line.credit))
                .map(line => {
                    const isForeign = line.currency !== 'EGP';
                    const amountInLineCurrency = line.debit! > 0 ? line.amountForeign : (line.credit! > 0 ? line.amountForeign : undefined);

                    return {
                        accountId: line.accountId!,
                        debit: line.debit!,
                        credit: line.credit!,
                        amountForeign: isForeign ? amountInLineCurrency : undefined,
                        currency: isForeign ? line.currency : undefined,
                        conversionRate: isForeign ? line.conversionRate : undefined,
                    };
                });

            if (finalLines.length < 2) { setError('يجب أن يحتوي القيد على حسابين على الأقل.'); return; }
        }

        const newEntryData: Omit<JournalEntry, 'id'> = { date, description, lines: finalLines, referenceNumber: referenceNumber.trim() || undefined, transactionType };
        if (showCheckDetails && checkNumber) {
            newEntryData.checkDetails = {
                checkNumber: checkNumber,
                checkDate: checkDate,
            };
        }

        await addJournalEntry(newEntryData);
        resetAllForms();
        setTransactionType(transactionType);
    };

    const totalDebit = lines.reduce((sum, line) => sum + (line.debit || 0), 0);
    const totalCredit = lines.reduce((sum, line) => sum + (line.credit || 0), 0);
    const isBalanced = Math.abs(totalDebit - totalCredit) < 0.01;
    const isPristine = totalDebit === 0 && totalCredit === 0;

    return (
        <div className="bg-primary p-6 rounded-2xl shadow-neumo">
            <h2 className="text-2xl font-bold mb-6 text-text-primary">إضافة حركة محاسبية</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
                    <input type="date" value={date} onChange={e => { setDate(e.target.value); setHasChanged(true); }} required className="p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary"/>
                    <input type="text" value={description} onChange={e => { setDescription(e.target.value); setHasChanged(true); }} placeholder="وصف الحركة" required className="p-3 bg-primary rounded-xl shadow-neumo-inset-sm lg:col-span-2 text-text-primary placeholder:text-text-secondary/80"/>
                    <input type="text" value={referenceNumber} onChange={e => { setReferenceNumber(e.target.value); setHasChanged(true); }} placeholder="رقم مرجعي (اختياري)" className="p-3 bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary placeholder:text-text-secondary/80"/>
                    <select value={transactionType} onChange={handleTransactionTypeChange} className="p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none font-bold text-text-primary">
                        <option value="general">قيد يومية عام</option>
                        <option value="receipt">سند قبض</option>
                        <option value="payment">سند صرف</option>
                    </select>
                </div>

                <hr className="border-primary-dark/20 my-4" />

                {transactionType === 'general' ? (
                    <>
                        <div className="overflow-x-auto">
                            <table className="w-full min-w-[800px]">
                                <thead><tr>
                                    <th className="p-2 text-right text-sm font-semibold">الحساب</th>
                                    <th className="p-2 text-center text-sm font-semibold">العملة</th>
                                    <th className="p-2 text-center text-sm font-semibold">سعر الصرف</th>
                                    <th className="p-2 text-center text-sm font-semibold">مدين (عملة السطر)</th>
                                    <th className="p-2 text-center text-sm font-semibold">دائن (عملة السطر)</th>
                                    <th className="p-2 text-center text-sm font-semibold">مدين (مُعادل مصري)</th>
                                    <th className="p-2 text-center text-sm font-semibold">دائن (مُعادل مصري)</th>
                                    <th></th>
                                </tr></thead>
                                <tbody>{lines.map((line, index) => {
                                    const debitInLineCurrency = (line.debit! > 0) ? (line.currency === 'EGP' ? line.debit : line.amountForeign) : '';
                                    const creditInLineCurrency = (line.credit! > 0) ? (line.currency === 'EGP' ? line.credit : line.amountForeign) : '';

                                    return (
                                        <tr key={index} className="space-y-2">
                                            <td><select value={line.accountId} onChange={e => handleLineChange(index, 'accountId', e.target.value)} required className="w-full p-2 bg-primary rounded-lg shadow-neumo-inset-sm appearance-none text-text-primary"><option value="">اختر حساب</option>{accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.id} - {acc.name}</option>)}</select></td>
                                            <td><input type="text" value={line.currency || ''} onChange={e => handleLineChange(index, 'currency', e.target.value)} className="w-20 p-2 text-center bg-primary rounded-lg shadow-neumo-inset-sm text-text-primary"/></td>
                                            <td><input type="number" step="0.01" value={line.conversionRate || ''} onChange={e => handleLineChange(index, 'conversionRate', e.target.value)} disabled={line.currency === 'EGP'} className="w-24 p-2 text-center bg-primary rounded-lg shadow-neumo-inset-sm disabled:bg-primary-dark/20 text-text-primary"/></td>
                                            <td><input type="number" step="0.01" value={debitInLineCurrency || ''} onChange={e => handleLineChange(index, 'debitForeign', e.target.value)} disabled={line.credit! > 0} className="w-32 p-2 text-center bg-primary rounded-lg shadow-neumo-inset-sm text-text-primary"/></td>
                                            <td><input type="number" step="0.01" value={creditInLineCurrency || ''} onChange={e => handleLineChange(index, 'creditForeign', e.target.value)} disabled={line.debit! > 0} className="w-32 p-2 text-center bg-primary rounded-lg shadow-neumo-inset-sm text-text-primary"/></td>
                                            <td><input type="number" step="0.01" value={line.debit || ''} readOnly className="w-32 p-2 text-center bg-primary-dark/20 rounded-lg shadow-neumo-inset-sm font-bold text-text-primary"/></td>
                                            <td><input type="number" step="0.01" value={line.credit || ''} readOnly className="w-32 p-2 text-center bg-primary-dark/20 rounded-lg shadow-neumo-inset-sm font-bold text-text-primary"/></td>
                                            <td><button type="button" onClick={() => removeLine(index)} disabled={lines.length <= 2} className="text-red-500 disabled:text-gray-400 p-2"><X size={20} /></button></td>
                                        </tr>
                                    )
                                })}</tbody>
                            </table>
                        </div>
                        <div className="flex justify-between items-center pt-2">
                            <button type="button" onClick={addLine} className="flex items-center gap-2 px-4 py-2 bg-primary text-text-primary rounded-xl hover:shadow-neumo-inset shadow-neumo-sm font-semibold"><Plus size={18} /><span>إضافة سطر</span></button>
                            <div className={`flex items-center gap-4 font-bold text-lg p-2 rounded-lg ${!isBalanced && !isPristine ? 'bg-red-100 dark:bg-red-500/20 text-red-700 dark:text-red-300' : 'text-text-primary'}`}>
                                {!isBalanced && !isPristine && <AlertTriangle size={20}/>}
                                <span className="text-debit">مدين: {totalDebit.toLocaleString()}</span><span>|</span><span className="text-credit">دائن: {totalCredit.toLocaleString()}</span>
                            </div>
                        </div>
                    </>
                ) : (
                    <>
                        {showCheckDetails && (
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-3 bg-blue-100 dark:bg-blue-900/30 border-l-4 border-blue-500 rounded-md">
                                <div><label className="font-semibold text-blue-800 dark:text-blue-300 block mb-1">رقم الشيك</label><input type="text" value={checkNumber} onChange={e => {setCheckNumber(e.target.value); setHasChanged(true);}} placeholder="رقم الشيك..." className="w-full p-2 text-lg font-bold text-center bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary"/></div>
                                <div><label className="font-semibold text-blue-800 dark:text-blue-300 block mb-1">تاريخ الشيك</label><input type="date" value={checkDate} onChange={e => {setCheckDate(e.target.value); setHasChanged(true);}} className="w-full p-2 text-lg font-bold text-center bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary"/></div>
                            </div>
                        )}
                        {isForeignCurrency && (
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 p-3 bg-blue-100 dark:bg-blue-900/30 border-l-4 border-blue-500 rounded-md">
                                <div className="md:col-span-1"><label className="font-semibold text-blue-800 dark:text-blue-300 block mb-1">العملة الأجنبية</label><input type="text" value={foreignCurrency} onChange={e => setForeignCurrency(e.target.value)} className="w-full p-2 text-lg font-bold text-center bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary"/></div>
                                <div className="md:col-span-1"><label className="font-semibold text-blue-800 dark:text-blue-300 block mb-1">سعر الصرف</label><input type="number" step="0.01" value={conversionRate} onChange={e => setConversionRate(Number(e.target.value))} required className="w-full p-2 text-lg font-bold text-center bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary"/></div>
                                <div className="md:col-span-1"><label className="font-semibold text-blue-800 dark:text-blue-300 block mb-1">المبلغ بالجنيه</label><input type="text" value={(amount * conversionRate).toLocaleString()} readOnly className="w-full p-2 text-lg font-bold text-center bg-primary-dark/20 rounded-xl shadow-neumo-inset-sm text-text-primary"/></div>
                            </div>
                        )}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                             <div className="md:col-span-1"><label className="font-semibold text-text-secondary block mb-2">{isForeignCurrency ? `المبلغ (${foreignCurrency})` : 'المبلغ'}</label><input type="number" step="0.01" value={amount || ''} onChange={e => { setAmount(Number(e.target.value)); setHasChanged(true); }} required placeholder="0.00" className="w-full p-3 text-lg font-bold text-center bg-primary rounded-xl shadow-neumo-inset-sm text-text-primary placeholder:text-text-secondary/80"/></div>
                            {transactionType === 'receipt' && <>
                                <div className="md:col-span-1"><label className="font-semibold text-text-secondary block mb-2">من حساب (العميل)</label><select value={fromAccountId} onChange={e => { setFromAccountId(e.target.value); setHasChanged(true); }} required className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none text-text-primary"><option value="">-- اختر العميل --</option>{customerAccounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name.replace('العملاء - ', '')}</option>)}</select></div>
                                <div className="md:col-span-1"><label className="font-semibold text-text-secondary block mb-2">إلى حساب (الخزينة/البنك)</label><select value={toAccountId} onChange={e => { setToAccountId(e.target.value); setHasChanged(true); }} required className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none text-text-primary"><option value="">-- اختر خزينة أو بنك --</option>{cashAndBankAccounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}</select></div>
                            </>}
                            {transactionType === 'payment' && <>
                                <div className="md:col-span-1"><label className="font-semibold text-text-secondary block mb-2">من حساب (الخزينة/البنك)</label><select value={fromAccountId} onChange={e => { setFromAccountId(e.target.value); setHasChanged(true); }} required className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none text-text-primary"><option value="">-- اختر خزينة أو بنك --</option>{cashAndBankAccounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}</select></div>
                                <div className="md:col-span-1"><label className="font-semibold text-text-secondary block mb-2">إلى حساب (المستفيد)</label><select value={toAccountId} onChange={e => { setToAccountId(e.target.value); setHasChanged(true); }} required className="w-full p-3 bg-primary rounded-xl shadow-neumo-inset-sm appearance-none text-text-primary"><option value="">-- اختر حساب الدفع --</option>{payableToAccounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}</select></div>
                            </>}
                        </div>
                    </>
                )}


                {error && <p className="text-red-500 bg-red-100 p-3 rounded-md text-center">{error}</p>}

                <button type="submit" className="w-full px-6 py-4 bg-accent text-white rounded-xl hover:bg-accent-dark font-bold text-lg shadow-md hover:shadow-lg transition-all">
                    حفظ الحركة
                </button>
            </form>
        </div>
    );
};


const Journal: React.FC<JournalProps> = ({ journalEntries, addJournalEntry, accounts, currentUser, setIsFormDirty, prefilledJournalLine, clearPrefill, onAccountClick, operations, onNavigateToOperation }) => {
    const [expandedEntry, setExpandedEntry] = useState<string | null>(null);
    const [viewingVoucher, setViewingVoucher] = useState<JournalEntry | null>(null);
    const canCreate = canPerformAction(currentUser.role, 'create');

    // Filter states
    const [searchQuery, setSearchQuery] = useState('');
    const [filterStartDate, setFilterStartDate] = useState(() => {
        const d = new Date();
        d.setMonth(d.getMonth() - 1);
        return d.toISOString().split('T')[0];
    });
    const [filterEndDate, setFilterEndDate] = useState(() => new Date().toISOString().split('T')[0]);
    const [filterType, setFilterType] = useState<TransactionType | 'all'>('all');
    const [filterAccount, setFilterAccount] = useState<string>('all');

    const transactionTypeMap: Record<TransactionType, string> = {
        general: 'قيد عام', payment: 'سند صرف', receipt: 'سند قبض',
        invoice: 'فاتورة', adjustment: 'تسوية',
    };

    const filteredEntries = useMemo(() => {
        return journalEntries
            .filter(entry => {
                const entryDate = entry.date;
                if (filterStartDate && entryDate < filterStartDate) return false;
                if (filterEndDate && entryDate > filterEndDate) return false;
                return true;
            })
            .filter(entry => {
                return filterType === 'all' || entry.transactionType === filterType;
            })
            .filter(entry => {
                return filterAccount === 'all' || entry.lines.some(line => line.accountId === filterAccount);
            })
            .filter(entry => {
                if (!searchQuery) return true;
                const query = searchQuery.toLowerCase();
                return entry.description.toLowerCase().includes(query) ||
                       (entry.referenceNumber && entry.referenceNumber.toLowerCase().includes(query));
            })
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    }, [journalEntries, filterStartDate, filterEndDate, filterType, filterAccount, searchQuery]);

    const groupedEntries = useMemo(() => {
        return filteredEntries.reduce((groups, entry) => {
            const date = entry.date;
            if (!groups[date]) {
                groups[date] = [];
            }
            groups[date].push(entry);
            return groups;
        }, {} as Record<string, JournalEntry[]>);
    }, [filteredEntries]);

    const resetFilters = () => {
        const d = new Date();
        d.setMonth(d.getMonth() - 1);
        setFilterStartDate(d.toISOString().split('T')[0]);
        setFilterEndDate(new Date().toISOString().split('T')[0]);
        setFilterType('all');
        setFilterAccount('all');
        setSearchQuery('');
    };

    const formatCurrency = (amount: number, currency?: string) => {
        const options = { style: 'currency', currency: currency || 'EGP', minimumFractionDigits: 2, maximumFractionDigits: 2 };
        return new Intl.NumberFormat(currency === 'EGP' || !currency ? 'ar-EG' : 'en-US', options).format(amount);
    };

    return (
    <div className="space-y-8">
        {viewingVoucher && (
            <Voucher
                entry={viewingVoucher}
                accounts={accounts}
                type={viewingVoucher.transactionType as 'receipt' | 'payment'}
                onClose={() => setViewingVoucher(null)}
            />
        )}
        <div className="no-print">
            {canCreate && <NewEntryForm addJournalEntry={addJournalEntry} accounts={accounts} journalEntries={journalEntries} setIsFormDirty={setIsFormDirty} prefilledJournalLine={prefilledJournalLine} clearPrefill={clearPrefill} />}
        </div>

        <div className="bg-primary p-6 rounded-2xl shadow-neumo printable-area">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-text-primary">سجل القيود</h2>
            </div>

            {/* Filter Section */}
            <div className="no-print bg-primary p-4 rounded-xl shadow-neumo-sm mb-6">
                 <div className="flex flex-wrap gap-4 items-end">
                    <div className="relative w-full md:w-auto flex-grow md:flex-grow-0">
                        <input
                            type="text"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            placeholder="بحث بالوصف أو الرقم المرجعي..."
                            className="w-full p-2 pl-8 bg-primary rounded-lg shadow-neumo-inset-sm focus:outline-none focus:ring-1 focus:ring-accent text-sm"
                        />
                        <Search size={16} className="absolute left-2 top-1/2 -translate-y-1/2 text-text-secondary" />
                    </div>
                    <div>
                        <label className="text-sm font-semibold text-text-secondary block mb-1">من تاريخ</label>
                        <input type="date" value={filterStartDate} onChange={e => setFilterStartDate(e.target.value)} className="w-full p-2 bg-primary rounded-lg shadow-neumo-inset-sm text-sm"/>
                    </div>
                    <div>
                        <label className="text-sm font-semibold text-text-secondary block mb-1">إلى تاريخ</label>
                        <input type="date" value={filterEndDate} onChange={e => setFilterEndDate(e.target.value)} className="w-full p-2 bg-primary rounded-lg shadow-neumo-inset-sm text-sm"/>
                    </div>
                    <div>
                        <label className="text-sm font-semibold text-text-secondary block mb-1">نوع الحركة</label>
                        <select value={filterType} onChange={e => setFilterType(e.target.value as any)} className="w-full p-2 bg-primary rounded-lg shadow-neumo-inset-sm appearance-none text-sm">
                            <option value="all">الكل</option>
                            {Object.entries(transactionTypeMap).map(([key, value]) => (
                                <option key={key} value={key}>{value}</option>
                            ))}
                        </select>
                    </div>
                    <div>
                        <label className="text-sm font-semibold text-text-secondary block mb-1">حسب الحساب</label>
                        <select value={filterAccount} onChange={e => setFilterAccount(e.target.value)} className="w-full p-2 bg-primary rounded-lg shadow-neumo-inset-sm appearance-none text-sm max-w-xs">
                            <option value="all">كل الحسابات</option>
                            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                        </select>
                    </div>
                     <button onClick={resetFilters} className="flex items-center justify-center gap-2 px-4 py-2 bg-primary text-accent rounded-md hover:shadow-neumo-inset shadow-neumo-sm font-semibold text-sm h-10">
                        <XCircle size={16}/> إعادة تعيين
                    </button>
                </div>
            </div>

            <div className="text-sm text-text-secondary mb-2 no-print">
                {`عرض ${filteredEntries.length} من إجمالي ${journalEntries.length} قيد.`}
            </div>

            <div className="space-y-6">
                {(Object.entries(groupedEntries) as [string, JournalEntry[]][]).map(([date, entries]) => (
                    <div key={date}>
                        <div className="sticky top-[-2rem] md:top-[-3rem] bg-primary-light z-10 py-2 -mx-8 px-8 print:static print:p-0 print:bg-transparent">
                             <div className="bg-primary px-4 py-1 rounded-full shadow-neumo-sm inline-block print:shadow-none print:bg-transparent print:border-b-2 print:border-black print:rounded-none print:inline">
                                <h3 className="text-lg font-bold text-text-secondary print:text-black">
                                   {new Date(date).toLocaleDateString('ar-EG', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                                </h3>
                            </div>
                        </div>
                        <div className="space-y-3 mt-2">
                            {entries.map(entry => {
                                const totalDebit = entry.lines.reduce((sum, line) => sum + line.debit, 0);
                                const type = entry.transactionType || 'general';
                                const typeName = transactionTypeMap[type] || 'قيد';
                                const linkedOp = operations.find(op => op.journalEntryId === entry.id);

                                const typeBadgeClass = {
                                    payment: 'bg-orange-100 text-orange-800 dark:bg-orange-900/50 dark:text-orange-300',
                                    receipt: 'bg-green-100 text-green-800 dark:bg-green-900/50 dark:text-green-300',
                                    invoice: 'bg-blue-100 text-blue-800 dark:bg-blue-900/50 dark:text-blue-300',
                                    general: 'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300',
                                    adjustment: 'bg-purple-100 text-purple-800 dark:bg-purple-900/50 dark:text-purple-300',
                                }[type];

                                return (
                                    <div key={entry.id} className="bg-primary rounded-xl shadow-neumo-sm overflow-hidden transition-shadow duration-300 hover:shadow-neumo">
                                        <div className="flex justify-between items-center p-4 cursor-pointer" onClick={() => setExpandedEntry(expandedEntry === entry.id ? null : entry.id)}>
                                            <div className="flex items-center gap-4 flex-1 min-w-0">
                                                <button className={`text-text-secondary transition-transform duration-300 ${expandedEntry === entry.id ? 'rotate-180' : ''}`}><ChevronDown size={20}/></button>
                                                <div className="flex-1 truncate">
                                                    <p className="font-semibold text-text-primary truncate" title={entry.description}>{entry.description}</p>
                                                    <div className="flex items-center gap-2 text-xs text-text-secondary mt-1">
                                                        <span className={`px-2 py-0.5 rounded-full font-bold ${typeBadgeClass}`}>{typeName}</span>
                                                        {entry.referenceNumber && <span>- #{entry.referenceNumber}</span>}

                                                        {linkedOp && (
                                                            <button
                                                                onClick={(e) => { e.stopPropagation(); onNavigateToOperation(linkedOp); }}
                                                                className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-purple-100 text-purple-800 hover:bg-purple-200 transition-colors text-xs font-bold border border-purple-200 dark:bg-purple-900/50 dark:text-purple-300 dark:border-purple-800"
                                                                title="الانتقال إلى تفاصيل العملية"
                                                            >
                                                                <Ship size={12} />
                                                                {linkedOp.code}
                                                            </button>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-4 flex-shrink-0 ml-4">
                                                <div className="text-left">
                                                    <p className="font-mono font-bold text-lg text-debit">{formatCurrency(totalDebit, 'EGP')}</p>
                                                </div>
                                                {(entry.transactionType === 'receipt' || entry.transactionType === 'payment') && (
                                                    <button onClick={(e) => { e.stopPropagation(); setViewingVoucher(entry); }} className="p-2 text-accent rounded-full hover:shadow-neumo-sm no-print" title="طباعة إيصال"><Receipt size={18} /></button>
                                                )}
                                            </div>
                                        </div>
                                         <div className={`transition-all duration-300 ease-in-out ${expandedEntry === entry.id ? 'max-h-[500px]' : 'max-h-0'}`}>
                                            <div className="bg-primary-light/30">
                                                <div className="p-4 border-t border-primary-dark/20">
                                                    {entry.checkDetails?.checkNumber && (
                                                        <div className="text-sm text-blue-700 dark:text-blue-300 font-semibold flex items-center gap-2 mb-2 p-2 bg-blue-100 dark:bg-blue-900/20 rounded-md">
                                                            <CreditCard size={16}/>
                                                            <span>شيك رقم: {entry.checkDetails.checkNumber}</span>
                                                            {entry.checkDetails.checkDate && <span>بتاريخ: {new Date(entry.checkDetails.checkDate).toLocaleDateString('ar-EG-u-nu-latn')}</span>}
                                                        </div>
                                                    )}
                                                    <table className="w-full text-right text-sm">
                                                        <thead className="border-b border-primary-dark/20">
                                                            <tr>
                                                                <th className="p-3 font-semibold">الحساب</th>
                                                                <th className="p-3 font-semibold text-center">مدين</th>
                                                                <th className="p-3 font-semibold text-center">دائن</th>
                                                            </tr>
                                                        </thead>
                                                        <tbody>{(entry.lines || []).map((line, index) => {
                                                            const account = accounts.find(acc => acc.id === line.accountId);
                                                            const isForeign = line.currency && line.currency !== 'EGP';
                                                            return (
                                                                <tr key={index} className={index % 2 !== 0 ? 'bg-primary/50 dark:bg-primary-dark/30' : ''}>
                                                                    <td className="p-3">
                                                                        <button onClick={() => onAccountClick(account!)} className="text-left w-full text-accent hover:underline font-semibold no-print">{account?.name}</button>
                                                                        <span className="print:inline hidden">{account?.name || 'غير معروف'}</span>
                                                                        {isForeign && <div className="text-xs text-blue-600 dark:text-blue-400 font-mono flex items-center gap-1"><Globe size={12}/>{formatCurrency(line.amountForeign!, line.currency)} @ {line.conversionRate}</div>}
                                                                    </td>
                                                                    <td className={`p-3 text-center font-mono ${line.debit > 0 ? 'text-debit' : ''}`}>{line.debit > 0 ? formatCurrency(line.debit, 'EGP') : '-'}</td>
                                                                    <td className={`p-3 text-center font-mono ${line.credit > 0 ? 'text-credit' : ''}`}>{line.credit > 0 ? formatCurrency(line.credit, 'EGP') : '-'}</td>
                                                                </tr>
                                                            )})}
                                                        </tbody>
                                                        <tfoot className="border-t-2 border-primary-dark/20 font-bold bg-primary-light/50">
                                                            <tr>
                                                                <td className="p-3">الإجمالي</td>
                                                                <td className="p-3 text-center font-mono text-debit">{formatCurrency(totalDebit, 'EGP')}</td>
                                                                <td className="p-3 text-center font-mono text-credit">{formatCurrency(entry.lines.reduce((s, l) => s + l.credit, 0), 'EGP')}</td>
                                                            </tr>
                                                        </tfoot>
                                                    </table>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))}
                 {Object.keys(groupedEntries).length === 0 && (
                    <div className="text-center p-8 text-text-secondary"><p>لا توجد قيود يومية تطابق معايير البحث.</p></div>
                )}
            </div>
        </div>
    </div>
    );
};

