const Layout: React.FC<LayoutProps> = (props) => {
    const { isFormDirty, setIsFormDirty } = props;
    const [activeView, setActiveView] = useState('dashboard');
    const [selectedAccount, setSelectedAccount] = useState<Account | null>(null);
    const [previousView, setPreviousView] = useState('dashboard');
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const { theme, toggleTheme } = useTheme();

    // Modal states
    const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
    const [isChartModalOpen, setIsChartModalOpen] = useState(false);
    const [isGuideOpen, setIsGuideOpen] = useState(false);
    const [startupAdvice, setStartupAdvice] = useState<{title: string; description: string}[] | null>(null);
    const [isGuideLoading, setIsGuideLoading] = useState(false);
    const [guideShownInSession, setGuideShownInSession] = useState(false);

    // State for pre-filling journal entries
    const [prefilledJournalLine, setPrefilledJournalLine] = useState<Partial<JournalEntryLine> | null>(null);

    // State for navigating to a specific operation
    const [targetOperationId, setTargetOperationId] = useState<string | null>(null);

    const handleNavigation = (viewId: string) => {
        if (isFormDirty) {
            if (window.confirm('لديك تغييرات غير محفوظة. هل تريد تجاهلها والمتابعة؟')) {
                setIsFormDirty(false); 
            } else {
                return; 
            }
        }
        setActiveView(viewId);
        setIsSidebarOpen(false); // Close sidebar on mobile on navigation
    };

    const handleNavigateToJournalWithPrefill = (account: Account) => {
        if (isFormDirty) {
            if (window.confirm('لديك تغييرات غير محفوظة سيتم فقدانها. هل تريد إنشاء قيد جديد على أي حال؟')) {
                setIsFormDirty(false);
            } else {
                return;
            }
        }

        const prefill: Partial<JournalEntryLine> = { accountId: account.id };
        setPrefilledJournalLine(prefill);
        setActiveView('journal'); 
    };

    const handleNavigateToOperation = (operation: Operation) => {
        if (isFormDirty) {
            if (window.confirm('لديك تغييرات غير محفوظة. هل تريد تجاهلها والمتابعة؟')) {
                setIsFormDirty(false); 
            } else {
                return; 
            }
        }
        setTargetOperationId(operation.id);
        setActiveView('operations');
    }

    const handleAccountSelect = (account: Account, parentView: string) => {
        setSelectedAccount(account);
        setPreviousView(parentView);
        setActiveView('accountDetail');
    };

    const handleBack = () => {
        setSelectedAccount(null);
        setActiveView(previousView);
    };

    // AI Startup Guide logic
    useEffect(() => {
        const isFreshStart = props.journalEntries.length === 0 && props.operations.length === 1 && props.operations[0].code === '2311-002-03';
        if (isFreshStart && !guideShownInSession) {
            const fetchAdvice = async () => {
                setIsGuideOpen(true);
                setIsGuideLoading(true);
                try {
                    const advice = await getStartupAdvice(props.accounts);
                    setStartupAdvice(advice);
                } catch (error) {
                    console.error("Failed to get startup advice:", error);
                    setStartupAdvice([{ title: "خطأ في الاتصال", description: "لم نتمكن من تحميل إرشادات البدء من مساعد الذكاء الاصطناعي. يرجى التحقق من اتصالك بالإنترنت والمحاولة مرة أخرى." }]);
                } finally {
                    setIsGuideLoading(false);
                    setGuideShownInSession(true); // Mark as shown for this session
                }
            };
            fetchAdvice();
        }
    }, [props.journalEntries, props.operations, props.accounts, guideShownInSession]);


    const renderActiveView = () => {
        // Handle detail view first
        if (activeView === 'accountDetail' && selectedAccount) {
            return <AccountDetailView account={selectedAccount} journalEntries={props.journalEntries} accounts={props.accounts} />;
        }

        switch (activeView) {
            case 'dashboard': return <Dashboard journalEntries={props.journalEntries} accounts={props.accounts} operations={props.operations} tasks={props.tasks} setActiveView={setActiveView} lowBalanceThreshold={props.lowBalanceThreshold} updateLowBalanceThreshold={props.updateLowBalanceThreshold} currentUser={props.currentUser} dashboardWidgets={props.dashboardWidgets} updateDashboardWidgets={props.updateDashboardWidgets} lowBalanceLog={props.lowBalanceLog} addLowBalanceRecord={props.addLowBalanceRecord} clearLowBalanceLog={props.clearLowBalanceLog} />;
            case 'operations': return <Operations operations={props.operations} accounts={props.accounts} addOperation={props.addOperation} updateOperation={props.updateOperation} deleteOperation={props.deleteOperation} currentUser={props.currentUser} setIsFormDirty={setIsFormDirty} journalEntries={props.journalEntries} linkOperationToJournalEntry={props.linkOperationToJournalEntry} onNavigateToJournal={setActiveView} priceLists={props.priceLists} documents={props.documents} addDocument={props.addDocument} deleteDocument={props.deleteDocument} linkExistingDocuments={props.linkExistingDocuments} initialOperationId={targetOperationId} onClearInitialOperation={() => setTargetOperationId(null)} />;
            case 'journal': return <Journal journalEntries={props.journalEntries} addJournalEntry={props.addJournalEntry} accounts={props.accounts} currentUser={props.currentUser} setIsFormDirty={setIsFormDirty} prefilledJournalLine={prefilledJournalLine} clearPrefill={() => setPrefilledJournalLine(null)} onAccountClick={(acc) => handleAccountSelect(acc, 'journal')} operations={props.operations} onNavigateToOperation={handleNavigateToOperation} />;
            case 'payroll': return <Payroll {...props} />;
            case 'accounts': return <AccountListView accounts={props.accounts} journalEntries={props.journalEntries} onAccountSelect={handleAccountSelect} addGeneralAccount={props.addGeneralAccount} updateAccount={props.updateAccount} deleteAccount={props.deleteAccount} currentUser={props.currentUser} onNewJournalEntry={handleNavigateToJournalWithPrefill} documents={props.documents} />;
            case 'customerManagement': return <CustomerManagement accounts={props.accounts} operations={props.operations} journalEntries={props.journalEntries} onAccountSelect={handleAccountSelect} addCustomer={props.addCustomer} updateAccount={props.updateAccount} deleteAccount={props.deleteAccount} currentUser={props.currentUser} priceLists={props.priceLists} addPriceList={props.addPriceList} updatePriceList={props.updatePriceList} deletePriceList={props.deletePriceList} documents={props.documents} />;
            case 'bankAndCash': return <AccountsManagement accounts={props.accounts} journalEntries={props.journalEntries} onAccountSelect={handleAccountSelect} addAccount={props.addAccount} updateAccount={props.updateAccount} deleteAccount={props.deleteAccount} currentUser={props.currentUser} onNewJournalEntry={handleNavigateToJournalWithPrefill} documents={props.documents} />;
