                            {(filterType !== 'all' || filterStatus !== 'all' || filterClient !== 'all' || searchQuery) && (
                                <button 
                                    onClick={() => { setFilterType('all'); setFilterStatus('all'); setFilterClient('all'); setSearchQuery(''); }} 
