                                                <button onClick={() => handleOpenInvoice(op)} className="p-2 text-gray-600 bg-gray-100 rounded-full hover:bg-gray-200" title="إصدار فاتورة"><FileText size={16} /></button>
                                                {canDelete && <button onClick={() => deleteOperation(op.id)} className="p-2 text-red-500 bg-red-50 rounded-full hover:bg-red-100" title="حذف"><Trash2 size={16} /></button>}
                                            </div>
                                        </td>
