                                    <td className="p-4 no-print"></td>
                                </tr>
                            </tfoot>
                        </table>
                        {filteredOperations.length === 0 && <p className="text-center text-text-secondary p-8">لا توجد عمليات تطابق الفلتر الحالي.</p>}
