                setPriceLists(prev => prev.filter(pl => pl.id !== id));
                setIsFormDirty(true);
            }
        });
    };


  // --- User CRUD functions ---
  const addUser = (user: Omit<User, 'id'>) => {
    const newUser = { ...user, id: uuidv4() };
    setUsers(prev => [...prev, newUser]);
    setIsFormDirty(true);
    addAuditLogEntry({ action: 'create', entityType: 'User', entityId: newUser.id, entityDescription: newUser.username });
  };

  const updateUser = (updatedUser: User) => {
    const oldUser = users.find(u => u.id === updatedUser.id);
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (currentUser?.id === updatedUser.id) {
        setCurrentUser(updatedUser);
    }
    setIsFormDirty(true);

    if (oldUser) {
        const changes = getChanges(oldUser, updatedUser);
        // Don't log password changes for security
        const filteredChanges = changes.filter(c => c.field !== 'password');
        if (filteredChanges.length > 0) {
            addAuditLogEntry({
                action: 'update',
                entityType: 'User',
                entityId: updatedUser.id,
                entityDescription: updatedUser.username,
                changes: filteredChanges,
            });
        }
    }
  };

  const deleteUser = (id: string) => {
    if (currentUser?.id === id) {
      alert("لا يمكنك حذف حسابك الحالي.");
      return;
    }
    const userToDelete = users.find(u => u.id === id);
    if (!userToDelete) return;

    requestConfirmation({
        title: 'تأكيد الحذف',
        message: `هل أنت متأكد من حذف المستخدم "${userToDelete?.username}"؟`,
        onConfirm: () => {
            setUsers(prev => prev.filter(u => u.id !== id));
            setIsFormDirty(true);
            addAuditLogEntry({ action: 'delete', entityType: 'User', entityId: userToDelete.id, entityDescription: userToDelete.username });
        }
    });
  };

  // --- File System Functions ---
  const handleRestoreData = (data: any, selections: Record<string, boolean>) => {
    let restoredCount = 0;
    const setters: Record<string, (d: any) => void> = {
        accounts: setAccounts,
        journalEntries: setJournalEntries,
        operations: setOperations,
        priceLists: setPriceLists,
        documents: setDocuments,
        tasks: setTasks,
        employees: setEmployees,
        attendance: setAttendance,
        payrollEntries: setPayrollEntries,
        users: setUsers,
        lowBalanceLog: setLowBalanceLog,
        auditLog: setAuditLog,
    };

    for (const key in selections) {
        if (selections[key] && data[key] && setters[key]) {
            setters[key](data[key]);
            restoredCount++;
        }
    }
    // Also restore settings if present in file
    if (data.lowBalanceThreshold) setLowBalanceThreshold(data.lowBalanceThreshold);
    if (data.dashboardWidgets) setDashboardWidgets(data.dashboardWidgets);

    return restoredCount > 0;
  };

 const handleDataReset = () => {
    const performReset = () => {
        // Structural data reset to defaults
        setAccounts(MOCK_ACCOUNTS);
        setUsers(MOCK_USERS);
        setEmployees(INITIAL_EMPLOYEES);
        setPriceLists(MOCK_PRICE_LISTS);
        // Transactional data cleared
        setJournalEntries([]);
        setOperations([]);
        setTasks([]);
        setAttendance({});
        setPayrollEntries([]);
        setDocuments([]);
        // Config reset
        setLowBalanceThreshold(5000);
        setLowBalanceLog([]);
        setAuditLog([]); // Also clear audit log
        // Reset file state
        setFileName('ملف محلي (LocalStorage)');
        setFileHandle(null);
        setStorageStatus('browser');
        setIsFormDirty(false);
        // Force re-login
        setCurrentUser(null)
        alert('تمت إعادة ضبط بيانات التطبيق بنجاح. سيتم تسجيل خروجك الآن.');
    };

    const confirmReset = () => {
        requestConfirmation({
            title: 'تحذير: إعادة ضبط المصنع',
            message: "سيؤدي هذا الإجراء إلى حذف جميع البيانات والعودة إلى الإعدادات الافتراضية. لا يمكن التراجع عن هذا الإجراء. هل أنت متأكد؟",
            onConfirm: performReset
        });
    };

    if (isFormDirty) {
        requestConfirmation({
            title: 'تغييرات غير محفوظة',
            message: 'لديك تغييرات غير محفوظة سيتم فقدانها. هل تريد إعادة الضبط على أي حال؟',
            onConfirm: confirmReset
        });
    } else {
        confirmReset();
    }
  };

  const handleNewDocument = () => {
    const createNew = () => {
        // Clear only transactional data, keep structural
        setJournalEntries([]);
        setOperations([]);
        setTasks([]);
        setAttendance({});
        setPayrollEntries([]);
        setLowBalanceLog([]);
        setDocuments([]);
        setAuditLog([]);

        // Reset file state
        setFileName('ملف جديد');
        setFileHandle(null);
        setStorageStatus('browser'); // Switch back to browser storage for new unsaved file
        setIsFormDirty(false);
        alert('تم إنشاء مستند جديد فارغ. (التخزين: المتصفح)');
    };

    if (isFormDirty) {
        requestConfirmation({
            title: 'تغييرات غير محفوظة',
            message: 'لديك تغييرات غير محفوظة. هل تريد إنشاء ملف جديد على أي حال؟',
            onConfirm: createNew
        });
    } else {
        createNew();
    }
  };

  // --- HARD DRIVE INTEGRATION ---
  const handleConnectLocalFile = async () => {
      try {
          // Check for API support
          if (!('showOpenFilePicker' in window)) {
              alert('عذراً، متصفحك لا يدعم الوصول المباشر للملفات. يرجى استخدام متصفح حديث مثل Chrome أو Edge.');
              return;
          }

          const [handle] = await (window as any).showOpenFilePicker({
              types: [{
                  description: 'ملفات بيانات JSON',
                  accept: { 'application/json': ['.json'] },
              }],
              multiple: false,
          });

          const file = await handle.getFile();
          const contents = await file.text();
          const data = JSON.parse(contents);

          // Restore data
          const allSelections = Object.keys(data).reduce((acc, key) => ({ ...acc, [key]: true }), {});
          if (handleRestoreData(data, allSelections)) {
              setFileHandle(handle);
              setFileName(file.name);
              setStorageStatus('disk');
              setLastSavedTime(new Date());
              setIsFormDirty(false);
              alert(`تم الاتصال بالملف "${file.name}" بنجاح. سيتم الحفظ تلقائياً على هذا الملف.`);
          } else {
              alert('الملف المحدد لا يحتوي على بيانات صالحة.');
          }

      } catch (err: any) {
          if (err.name !== 'AbortError') {
              console.error('Error opening file handle:', err);
              alert('حدث خطأ أثناء فتح الملف.');
          }
      }
  };

  const handleCreateLocalFile = async () => {
        try {
             if (!('showSaveFilePicker' in window)) {
                alert('عذراً، متصفحك لا يدعم الوصول المباشر للملفات.');
                return;
            }

            const handle = await (window as any).showSaveFilePicker({
                suggestedName: `Accounting_Data_${new Date().toISOString().split('T')[0]}.json`,
                types: [{
                    description: 'ملف بيانات JSON',
                    accept: { 'application/json': ['.json'] },
                }],
            });

            setFileHandle(handle);
            setFileName(handle.name);
            setStorageStatus('disk');

            // Force immediate save to new file
            const allData = {
                accounts, journalEntries, operations, tasks, employees, attendance, payrollEntries, users, priceLists, documents, auditLog,
                lowBalanceThreshold, dashboardWidgets, lowBalanceLog
            };
            const writable = await handle.createWritable();
            await writable.write(JSON.stringify(allData, null, 2));
            await writable.close();

            setLastSavedTime(new Date());
            setIsFormDirty(false);
            alert(`تم إنشاء الملف "${handle.name}" بنجاح. سيتم الحفظ عليه تلقائياً.`);

        } catch (err: any) {
            if (err.name !== 'AbortError') {
                console.error('Error creating file handle:', err);
                alert('حدث خطأ أثناء إنشاء الملف.');
            }
        }
  };

  // Legacy File Input Open (for browsers without File System API or simple upload)
  const handleOpenFile = () => {
     const open = () => {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.json,application/json';
        input.style.display = 'none';

        input.onchange = (event) => {
            document.body.removeChild(input);
            const target = event.target as HTMLInputElement;
            const file = target.files?.[0];
            if (!file) return;

            const reader = new FileReader();
            reader.onload = (e) => {
                try {
                    const contents = e.target?.result as string;
                    const data = JSON.parse(contents);

                    const allSelections = Object.keys(data).reduce((acc, key) => ({ ...acc, [key]: true }), {});
                    if (handleRestoreData(data, allSelections)) {
                        setFileName(file.name);
                        // Note: Loading via input type=file does NOT give write permission to original file.
                        // So we stay in 'browser' storage mode unless they use "Connect Local File".
                        setFileHandle(null);
                        setStorageStatus('browser'); 
                        setIsFormDirty(true); // Treat as imported data that needs saving
                        alert(`تم استيراد البيانات من "${file.name}". (التخزين الحالي: المتصفح)`);
                    } else {
                        alert('الملف المحدد لا يحتوي على بيانات صالحة.');
                    }
                } catch (err) {
                    console.error('Error opening file:', err);
                    alert('حدث خطأ أثناء فتح الملف.');
                }
            };
            reader.readAsText(file);
        };

        document.body.appendChild(input);
        input.click();
     };

     if (isFormDirty) {
        requestConfirmation({
            title: 'تغييرات غير محفوظة',
            message: 'لديك تغييرات غير محفوظة. هل تريد فتح ملف آخر وتجاهل التغييرات الحالية؟',
            onConfirm: open
        });
    } else {
        open();
    }
  };

  const handleSaveFile = (saveAs = false) => {
    // This is "Download as JSON", distinct from the continuous disk sync
    const allData = {
      accounts, journalEntries, operations, tasks, employees, attendance, payrollEntries, users, priceLists, documents, auditLog
    };

    try {
        const dataStr = JSON.stringify(allData, null, 2);
        const blob = new Blob([dataStr], { type: "application/json" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.download = fileName === 'ملف محلي (LocalStorage)' ? `محاسبة-${new Date().toISOString().split('T')[0]}.json` : fileName;
        link.href = url;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        // If we are in browser mode, saving a file manually counts as "saving" conceptually for the user,
        // though technically it doesn't persist to disk automatically.
        if (storageStatus === 'browser') {
             setIsFormDirty(false); 
        }
    } catch (err) {
       console.error('Error saving file:', err);
       alert('حدث خطأ أثناء حفظ الملف.');
    }
  };

  const handleExportData = () => {
    const allData = {
      accounts,
      journalEntries,
      operations,
      tasks,
      employees,
      attendance,
      payrollEntries,
      users,
      priceLists,
      documents,
      auditLog,
      // also include settings for a complete backup
      lowBalanceThreshold,
      dashboardWidgets,
      lowBalanceLog,
    };

    try {
      const dataStr = JSON.stringify(allData, null, 2);
      const blob = new Blob([dataStr], { type: "application/json;charset=utf-8;" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.download = `accounting_export_${new Date().toISOString().split('T')[0]}.json`;
      link.href = url;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
      alert('تم تصدير البيانات بنجاح.');
    } catch (err) {
      console.error('Error exporting data:', err);
      alert('حدث خطأ أثناء تصدير البيانات.');
    }
  };

  const handleImportCsv = (csvString: string, dataType: 'accounts') => {
    if (dataType !== 'accounts') {
      alert('استيراد هذا النوع من البيانات غير مدعوم حاليًا.');
      return;
    }

    try {
      const lines = csvString.trim().split(/\r?\n/);
      if (lines.length < 2) {
        alert('ملف CSV فارغ أو يحتوي على رؤوس فقط.');
        return;
      }

      const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replace(/"/g, ''));
      const requiredHeaders = ['id', 'name', 'type'];
      if (!requiredHeaders.every(h => headers.includes(h))) {
        alert(`ملف CSV يجب أن يحتوي على الأعمدة التالية على الأقل: ${requiredHeaders.join(', ')}`);
        return;
      }

      const newAccounts: Account[] = [];
      let skippedCount = 0;

      for (let i = 1; i < lines.length; i++) {
        const values = lines[i].split(',');
        const rowData: any = {};
        headers.forEach((header, index) => {
          rowData[header] = values[index]?.trim().replace(/"/g, '') || '';
        });

        if (!rowData.id || !rowData.name || !rowData.type) continue;

        if (accounts.some(acc => acc.id === rowData.id)) {
          skippedCount++;
          continue;
        }

        const newAccount: Account = {
          id: rowData.id,
          name: rowData.name,
          type: rowData.type as AccountType,
          openingBalance: parseFloat(rowData.openingbalance) || 0,
          notes: rowData.notes || '',
          currency: rowData.currency || 'EGP',
          isBankOrCash: rowData.isbankorcash === 'true',
          category: rowData.category as 'safe' | 'bank' || undefined,
          currencyType: rowData.currencytype as 'local' | 'foreign' || undefined,
          conversionRate: parseFloat(rowData.conversionrate) || undefined,
          country: rowData.country || '',
          accountNumber: rowData.accountnumber || '',
          email: rowData.email || '',
          phone: rowData.phone || '',
          address: rowData.address || '',
          taxNumber: rowData.taxnumber || '',
          bankName: rowData.bankname || '',
          bankAccountNumber: rowData.bankaccountnumber || '',
          bankCurrency: rowData.bankcurrency || '',
        };
        newAccounts.push(newAccount);
      }

      if (newAccounts.length > 0) {
        setAccounts(prev => [...prev, ...newAccounts].sort((a,b) => a.id.localeCompare(b.id)));
        setIsFormDirty(true);
      }
      alert(`اكتمل الاستيراد. تم إضافة ${newAccounts.length} حساب جديد. تم تخطي ${skippedCount} حساب مكرر.`);

    } catch (error) {
      console.error('Error importing CSV:', error);
      alert('حدث خطأ أثناء معالجة ملف CSV. يرجى التأكد من أن التنسيق صحيح.');
    }
  };

  if (isLoading) {
    return (
        <ThemeProvider>
            <LoadingScreen />
        </ThemeProvider>
    );
  }

  if (!currentUser) {
    return (
        <ThemeProvider>
            <Login onLogin={handleLogin} users={users} />
        </ThemeProvider>
    );
  }

  return (
    <ThemeProvider>
        <ChartStyleProvider>
        <ConfirmationDialog
            isOpen={confirmation.isOpen}
            title={confirmation.title}
            message={confirmation.message}
            onConfirm={confirmation.onConfirm}
            onCancel={handleCancelConfirmation}
            confirmVariant={confirmation.confirmVariant}
        />
        <Layout
            currentUser={currentUser}
            accounts={accounts}
            journalEntries={journalEntries}
            operations={operations}
            priceLists={priceLists}
            documents={documents}
            tasks={tasks}
            employees={employees}
            attendance={attendance}
            payrollEntries={payrollEntries}
            users={users}
            lowBalanceThreshold={lowBalanceThreshold}
            dashboardWidgets={dashboardWidgets}
            lowBalanceLog={lowBalanceLog}
            auditLog={auditLog}
            onLogout={handleLogout}
            addJournalEntry={addJournalEntry}
            addAccount={addAccount}
            addGeneralAccount={addGeneralAccount}
            addCustomer={addCustomer}
            updateAccount={updateAccount}
            deleteAccount={deleteAccount}
            addOperation={addOperation}
            updateOperation={updateOperation}
            deleteOperation={deleteOperation}
            linkOperationToJournalEntry={linkOperationToJournalEntry}
            addPriceList={addPriceList}
            updatePriceList={updatePriceList}
            deletePriceList={deletePriceList}
            addDocument={addDocument}
            deleteDocument={deleteDocument}
            linkExistingDocuments={linkExistingDocuments}
            addTask={addTask}
            toggleTask={toggleTask}
            removeTask={removeTask}
            addEmployee={addEmployee}
            updateEmployee={updateEmployee}
            deleteEmployee={deleteEmployee}
            updateAttendance={updateAttendance}
            addPayrollEntry={addPayrollEntry}
            updatePayrollEntry={updatePayrollEntry}
            deletePayrollEntry={deletePayrollEntry}
            addUser={addUser}
            updateUser={updateUser}
            deleteUser={deleteUser}
            updateLowBalanceThreshold={updateLowBalanceThreshold}
            updateDashboardWidgets={updateDashboardWidgets}
            addLowBalanceRecord={addLowBalanceRecord}
            clearLowBalanceLog={clearLowBalanceLog}
            handleDataReset={handleDataReset}
            handleExportData={handleExportData}
            handleImportCsv={handleImportCsv}
            isFormDirty={isFormDirty}
            setIsFormDirty={setIsFormDirty}
            fileName={fileName}
            storageStatus={storageStatus}
            lastSavedTime={lastSavedTime}
            handleNewDocument={handleNewDocument}
            handleOpenFile={handleOpenFile}
            handleSaveFile={handleSaveFile}
            handleConnectLocalFile={handleConnectLocalFile}
            handleCreateLocalFile={handleCreateLocalFile}
        />
        </ChartStyleProvider>
    </ThemeProvider>
  );
}

