        if (status === 'disk') {
            icon = <HardDrive size={16} />;
            text = 'حفظ محلي (القرص الصلب)';
            colorClass = 'text-green-600 bg-green-100';
        } else if (status === 'unsaved') {
            icon = <Save size={16} className="animate-pulse"/>;
            text = 'جاري الحفظ...';
            colorClass = 'text-amber-600 bg-amber-100';
        } else {
            icon = <Globe size={16} />;
