    const lines = csvString.trim().split(/\r?\n/);
    if (lines.length < 2) return;
    const headers = lines[0].split(',').map(h => h.trim().toLowerCase().replace(/"/g, ''));
    const newAccounts: Account[] = [];
    for (let i = 1; i < lines.length; i++) {
        const values = lines[i].split(',');
        const rowData: any = {};
        headers.forEach((header, index) => rowData[header] = values[index]?.trim().replace(/"/g, '') || '');
        if (!rowData.id || !rowData.name || !rowData.type || accounts.some(acc => acc.id === rowData.id)) continue;
        newAccounts.push({
            id: rowData.id, name: rowData.name, type: rowData.type as AccountType, openingBalance: parseFloat(rowData.openingbalance) || 0, notes: rowData.notes || '', currency: rowData.currency || 'EGP', isBankOrCash: rowData.isbankorcash === 'true', category: rowData.category as 'safe' | 'bank' || undefined, currencyType: rowData.currencytype as 'local' | 'foreign' || undefined, conversionRate: parseFloat(rowData.conversionrate) || undefined, country: rowData.country || '', accountNumber: rowData.accountnumber || '', email: rowData.email || '', phone: rowData.phone || '', address: rowData.address || '', taxNumber: rowData.taxnumber || '', bankName: rowData.bankname || '', bankAccountNumber: rowData.bankaccountnumber || '', bankCurrency: rowData.bankcurrency || '',
        });
    }
    if (newAccounts.length > 0) {
        setAccounts(prev => [...prev, ...newAccounts].sort((a,b) => a.id.localeCompare(b.id)));
        setIsFormDirty(true);
    }
  };

  if (isLoading) return <ThemeProvider><LoadingScreen /></ThemeProvider>;
  if (!currentUser) return <ThemeProvider><Login onLogin={handleLogin} users={users} /></ThemeProvider>;

  return (
    <ThemeProvider>
        <ChartStyleProvider>
        <ConfirmationDialog isOpen={confirmation.isOpen} title={confirmation.title} message={confirmation.message} onConfirm={confirmation.onConfirm} onCancel={handleCancelConfirmation} confirmVariant={confirmation.confirmVariant} />
        <Layout currentUser={currentUser} accounts={accounts} journalEntries={journalEntries} operations={operations} priceLists={priceLists} documents={documents} tasks={tasks} employees={employees} attendance={attendance} payrollEntries={payrollEntries} users={users} lowBalanceThreshold={lowBalanceThreshold} dashboardWidgets={dashboardWidgets} lowBalanceLog={lowBalanceLog} auditLog={auditLog} onLogout={handleLogout} addJournalEntry={addJournalEntry} addAccount={addAccount} addGeneralAccount={addGeneralAccount} addCustomer={addCustomer} updateAccount={updateAccount} deleteAccount={deleteAccount} addOperation={addOperation} updateOperation={updateOperation} deleteOperation={deleteOperation} linkOperationToJournalEntry={linkOperationToJournalEntry} addPriceList={addPriceList} updatePriceList={updatePriceList} deletePriceList={deletePriceList} addDocument={addDocument} deleteDocument={deleteDocument} linkExistingDocuments={linkExistingDocuments} addTask={addTask} toggleTask={toggleTask} removeTask={removeTask} addEmployee={addEmployee} updateEmployee={updateEmployee} deleteEmployee={deleteEmployee} updateAttendance={updateAttendance} addPayrollEntry={addPayrollEntry} updatePayrollEntry={updatePayrollEntry} deletePayrollEntry={deletePayrollEntry} addUser={addUser} updateUser={updateUser} deleteUser={deleteUser} updateLowBalanceThreshold={updateLowBalanceThreshold} updateDashboardWidgets={updateDashboardWidgets} addLowBalanceRecord={addLowBalanceRecord} clearLowBalanceLog={clearLowBalanceLog} handleDataReset={handleDataReset} handleExportData={handleExportData} handleImportCsv={handleImportCsv} isFormDirty={isFormDirty} setIsFormDirty={setIsFormDirty} fileName={fileName} storageStatus={storageStatus} lastSavedTime={lastSavedTime} handleNewDocument={handleNewDocument} handleOpenFile={handleOpenFile} handleSaveFile={handleSaveFile} handleConnectLocalFile={handleConnectLocalFile} handleCreateLocalFile={handleCreateLocalFile} />
        </ChartStyleProvider>
    </ThemeProvider>
  );
}

export default App;

